mapper.select:
/* oms-po-poPlanReq-sql-oracle.xml - selectTOrderPoPlanReq */ #{GRIDPAGING_ROWNUMTYPE_TOP} WITH REQ_MST AS ( SELECT /* hint: MATERIALIZE */ OWKEY ,CTKEY ,ICKEY,REQORDERTYPE ,NEEDDAYS , EAUOM AS IC_EA, INNUOM AS IC_INN, CTNUOM AS IC_CTN, CPPUOM AS IC_CPP , VOL FROM TORDER_MST_REQORDER WHERE OWKEY =#{owkey} AND REQORDERTYPE ='03' AND CTKEY =#{CTKEY}
AND ICKEY IN
#{item}
) SELECT '0' AS CHK, X.REQCTKEY, CT.CTNM AS REQCTNM, COALESCE(X.REQORDERDAY, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')) AS REQORDERDAY, 'N' AS URGENCYREQORDERYN, COALESCE(X.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN, CASE WHEN X.UPLOADYN = 'Y' THEN '업로드' ELSE '자동' END AS UPLOADYN , /* 센터재고 반영 필요 발주량 (개/중포/카톤/팔레트) */ X.REQQTY AS IVRFLCTNEEDQTYEA, TRUNC( COALESCE(X.REQQTY, 0) / NULLIF(COALESCE(X.IC_INN, 1),0) , 2) AS IVRFLCTNEEDQTYINN, TRUNC( COALESCE(X.REQQTY, 0) / NULLIF(COALESCE(X.IC_CTN, 1),0) , 2) AS IVRFLCTNEEDQTYCTN, TRUNC(COALESCE(X.REQQTY, 0)/ NULLIF(COALESCE(X.IC_CTN, 1) * NULLIF(CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE NULL END,0), 0) , 2) AS IVRFLCTNEEDQTYPLT,
/* 발주구역/타겟 */ CASE WHEN X.REQORDERAR IS NOT NULL THEN X.REQORDERAR WHEN X.MEASUREMENTYN ='N' THEN 'N' WHEN X.ASRTYN ='Y' THEN 'T' WHEN X.REQCTKEY ='05'THEN X.ANSUNGB2BPOCTG WHEN X.REQCTKEY ='04'THEN X.BUSANB2BPOCTG WHEN X.REQCTKEY ='01'THEN X.NAMSAB2BPOCTG ELSE '' END AS REQORDERAR, X.ANSUNGB2BPOCTG, X.BUSANB2BPOCTG, X.NAMSAB2BPOCTG, X.LCKEY AS ICTGT, /* 상태/유형 */ COALESCE(X.REQORDERSTATUS, '') AS REQORDERSTATUS, Y.COMDTNM AS REQORDERSTATUSNM, COALESCE(X.REQORDERTYPE, '03') AS REQORDERTYPE , -- 03 : 이고발주 Z.COMDTNM AS REQORDERTYPENM, /* 키/식별자 */ COALESCE(X.SEQ, 0) AS SEQ, COALESCE(X.OWKEY, '') AS OWKEY, COALESCE(X.CTKEY, '') AS CTKEY, /* 상품정보 */ COALESCE(X.ICKEY, '') AS ICKEY, COALESCE(X.ICNM, '') AS ICNM, COALESCE(X.ASRTYN, '') AS ASRTYN, COALESCE(X.ACNM, '') AS ACNM, COALESCE(X.IC_EA, 0) AS ICEA, COALESCE(X.IC_INN, 0) AS ICINN, COALESCE(X.IC_CTN, 0) AS ICCTN, COALESCE(X.IC_CPP, 0) AS ICCPP, /* 상품상태 */ COALESCE(X.UNICYN, '') AS UNICYN, COALESCE(X.DSPYN, '') AS DSPYN, COALESCE(X.DLVRYYN, '') AS DLVRYYN, COALESCE(X.SALESTATUS, '') AS SALESTATUS, ZZ.COMDTNM AS SALESTATUSNM, COALESCE(X.POABLEYN, '') AS ABLEREQORDERYN, /* 일/월평균 출고량 */ COALESCE(X.DAYQTY, 0) AS EADAYAVGOBQTY, COALESCE(X.INNDAYQTY, 0) AS INNDAYAVGOBQTY, COALESCE(X.CTNDAYQTY, 0) AS CTNDAYAVGOBQTY, COALESCE(X.PLTDAYQTY, 0) AS PLTDAYAVGOBQTY, COALESCE(X.MONTHQTY, 0) AS EAMONTHAVGOBQTY, COALESCE(X.INNMONTHQTY, 0) AS INNMONTHAVGOBQTY, COALESCE(X.CTNMONTHQTY, 0) AS CTNMONTHAVGOBQTY, COALESCE(X.PLTMONTHQTY, 0) AS PLTMONTHAVGOBQTY, /* B2B 센터 입고예정 */ COALESCE(X.IBEXPCTQTY01, 0) AS NAMSAIBEXPCTQTY, COALESCE(X.IBEXPCTQTY04, 0) AS BUSANIBEXPCTQTY, COALESCE(X.IBEXPCTQTY05, 0) AS ANSUNGIBEXPCTQTY, /* B2B 센터 재고 */ COALESCE(X.AVQTY01, 0) AS NAMSAAVQTY, COALESCE(X.AVQTY04, 0) AS BUSANAVQTY, COALESCE(X.AVQTY05, 0) AS ANSUNGAVQTY, /* B2B 일평균 */ COALESCE(X.AVGOBQTY01, 0) AS NAMSAAVGOBQTY, COALESCE(X.AVGOBQTY04, 0) AS BUSANAVGOBQTY, COALESCE(X.AVGOBQTY05, 0) AS ANSUNGAVGOBQTY, /* B2B 보장재고(일수*일평균) */ COALESCE(X.GRTIVDAYS01 * X.AVGOBQTY01, 0) AS NAMSAB2BCTGRTQTY, COALESCE(X.GRTIVDAYS04 * X.AVGOBQTY04, 0) AS BUSANB2BCTGRTQTY, COALESCE(X.GRTIVDAYS05 * X.AVGOBQTY05, 0) AS ANSUNGB2BCTGRTQTY, /* 온라인 재고/총재고/환산가용일 */ COALESCE(X.AVQTY, 0) AS AVQTY, COALESCE(X.B2CIBQTY, 0) AS B2CIBQTY, '' AS B2CIBYN, COALESCE(X.TOTQTY, 0) AS TOTQTY, COALESCE(X.NOWCNVRTAVDAYS, 0) AS CALAVDAYS, /* 가용일/리드타임/발주 필요 가능일 */ COALESCE(X.CTLEADTIME_T, 0) AS CTLEADTIME, COALESCE(X.AVDAYS_T, 0) AS AVDAYS, COALESCE(X.PONEEDDAYS, 0) AS PONEEDDAYS, /* MD 요청 */ COALESCE(X.MDQTY, 0) AS MDREQQTY, COALESCE(X.MDCMDT, '') AS MDCMT, CASE WHEN X.REQORDERUNIT IS NOT NULL THEN X.REQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END AS REQORDERUNIT, CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END AS REQORDERQTY , CASE WHEN X.DLVYREQORDERUNIT IS NOT NULL THEN X.DLVYREQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END AS DLVYREQORDERUNIT, /* 파생: PLT/CTN/INN 환산 수량 */ TRUNC((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END ) / NULLIF( COALESCE(X.IC_CTN, 1) * COALESCE(CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END, 1) ,0) ,2) AS REQORDERPLT, TRUNC((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END) / NULLIF(COALESCE(X.IC_CTN, 1),0) ,2) AS REQORDERCTN , TRUNC((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END) / NULLIF(COALESCE(X.IC_INN, 1),0) ,2) AS REQORDERINN , CEIL(COALESCE((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY / X.IC_INN ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END), 0) * COALESCE(X.VOL, 0) * 100 ) / 100 AS REQCBM, CEIL(COALESCE((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END), 0) * COALESCE(X.SLPRC, 0) * 100) / 100 AS REQPRC , CASE WHEN CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END > X.B2BCARDBASEQTY THEN 'Excess Order Allowed' ELSE '' END AS CMT , X.CTNCRIT , X.PLTCRIT , X.INNCRIT , COALESCE(X.CPP01, '') AS NAMSACPP, COALESCE(X.CPP04, '') AS BUSANCPP, COALESCE(X.CPP05, '') AS ANSUNGCPP, CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END AS CPP , /* 부피/가격 원천 */ COALESCE(X.VOL, '') AS VOL, COALESCE(X.SLPRC, '') AS SLPRC, /* 예정가용일: (현 재고 - 일평균*리드타임 + 발주요청수량) / 일평균 */ TO_CHAR(TRUNC(( COALESCE(X.TOTQTY, 0) - (CASE COALESCE(X.DAYQTY, 0) WHEN 0 THEN 1 ELSE X.DAYQTY END * COALESCE(X.CTLEADTIME_T, 1)) + (CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END) ) / CASE COALESCE(X.DAYQTY, 0) WHEN 0 THEN 1 ELSE X.DAYQTY END,1), 'FM999,999,990.0') AS EXPCTAVDAYS, /* 평균 집계 기간 */ X.OBFROMDAY AS AVGOBFROMDAY, X.OBTODAY AS AVGOBTODAY, X.APLYDAYS AS AVGAPLYDAYS, /* 센터별 리드타임 */ X.CTLEADTIME05, X.CTLEADTIME04, X.CTLEADTIME01, /* 필요 발주량*/ X.PONEEDQTYEA, X.PONEEDQTYINN, X.PONEEDQTYCTN, CASE X.REQCTKEY WHEN '01' THEN TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.CPP01, 1),0), 2) WHEN '04' THEN TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.CPP04, 1),0), 2) WHEN '05' THEN TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.CPP05, 1),0), 2) ELSE TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.IC_CPP, 1),0), 2) END AS PONEEDQTYPLT , X.RECALCYN, X.CBMCLOSRNG, /* 감사 컬럼 */ COALESCE(X.INSERTDATE, '') AS INSERTDATE, COALESCE(X.INSERTURKEY, '') AS INSERTURKEY, COALESCE(X.UPDATEDATE, '') AS UPDATEDATE, COALESCE(X.UPDATEURKEY, '') AS UPDATEURKEY FROM ( SELECT T.* , CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) END AS PONEEDQTYEA
, CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE TRUNC( COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) / NULLIF(COALESCE(T.IC_INN, 1),0), 2) END AS PONEEDQTYINN
, CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE TRUNC( COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0), 2) END AS PONEEDQTYCTN , CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE TRUNC((COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0)) / NULLIF( COALESCE(T.IC_CTN, 1) * COALESCE(CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END, 0) , 0) , 2) END AS PONEEDQTYPLT /*싱글*/ , 0 AS CAND_QTY_INN , CASE /* 카톤 기준 환산 후 올림 */ WHEN CEIL( COALESCE(T.REQQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN CEIL( COALESCE(T.REQQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) /* 초과 시: 센터반영치 내에서 카톤 단위로 절사 */ ELSE FLOOR( COALESCE(T.B2BCARDBASEQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) END AS CAND_QTY_CTN , CASE WHEN T.CTNCRIT IS NULL THEN 0 WHEN ( T.REQQTY / COALESCE(T.IC_CTN, 1) * COALESCE(T.IC_CTN, 1) / NULLIF( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END , 0) ) >= T.CTNCRIT THEN LEAST( /* PLT 올림 후 수량 환산 */ CEIL( T.REQQTY / NULLIF( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END , 0) ) * ( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END ), /* 카드 기준 초과 방어 */ COALESCE(T.B2BCARDBASEQTY, 0) ) ELSE 0 END AS CAND_QTY_PLT
/*멀티*/ , CASE WHEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0) + (1 - COALESCE(T.INNCRIT, 0.5))) * COALESCE(T.IC_INN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0) + (1 - COALESCE(T.INNCRIT, 0.5))) * COALESCE(T.IC_INN, 1) ELSE FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0)) * COALESCE(T.IC_INN, 1) END AS CAND_QTY_INN , CASE WHEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0) + (1-COALESCE(T.CTNCRIT, 0.5))) * COALESCE(T.IC_CTN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0) + (1-COALESCE(T.CTNCRIT, 0.5))) * COALESCE(T.IC_CTN, 1) ELSE FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0)) * COALESCE(T.IC_CTN, 1) END AS CAND_QTY_CTN , CASE WHEN COALESCE(T.IC_CTN, 0)=0 THEN NULL WHEN COALESCE(CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END, 0)=0 THEN NULL ELSE CASE WHEN FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) + (1-COALESCE(T.PLTCRIT, 0.5)) ) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) + (1-COALESCE(T.PLTCRIT, 0.5)) ) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) ELSE FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0))) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) END END AS CAND_QTY_PLT
FROM (
SELECT S.* /* 센터재고 반영 필요 발주량 : 필요발주량 – (B2B재고수량 – (보장재고일수 * 오프라인일 평균수량 )) 각센터별 센터재고 반영 필요 발주량 */ , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0))) END AS REQQTY01 , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0))) END AS REQQTY04 , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0))) END AS REQQTY05 , CASE WHEN (CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) ELSE 0 END) <= 0 THEN 0 ELSE LEAST( GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) /* B2B재고수량 - B2B보장재고 */ WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) ELSE 0 END ) END AS REQQTY /* 발주요청센터 반영 필요 발주량 해당수량 정보를 읽어서 발주 단위를 구한다. */ , GREATEST( 0, CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) /* 안성 */ WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) /* 부산 */ WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) /* 남사 */ ELSE 0 END ) AS B2BCARDBASEQTY
FROM ( SELECT F.* /* 발주 필요 가능일 : (가용일 + 센터 리드타임) - 현재 환산 가용일 [현재 환산가용일 : 총재고 / 일평균수량] */ , CASE WHEN F.CALAVDAYS IS NOT NULL THEN F.AVDAYS + F.CTLEADTIME - F.CALAVDAYS ELSE (CASE F.REQCTKEY WHEN '05' THEN F.CTLEADTIME05 + F.NEEDDAYS - F.NOWCNVRTAVDAYS WHEN '04' THEN F.CTLEADTIME04 + F.NEEDDAYS - F.NOWCNVRTAVDAYS WHEN '01' THEN F.CTLEADTIME01 + F.NEEDDAYS - F.NOWCNVRTAVDAYS ELSE 0 END) END AS PONEEDDAYS , COALESCE(F.AVDAYS, F.NEEDDAYS) AS AVDAYS_T /* B2B보장재고 */ , F.GRTIVDAYS01 * F.AVGOBQTY01 AS CTGRTQTY01 , F.GRTIVDAYS04 * F.AVGOBQTY04 AS CTGRTQTY04 , F.GRTIVDAYS05 * F.AVGOBQTY05 AS CTGRTQTY05 /* B2B센터 재고 + B2B입고예정정보 : B2B재고수량 */ , F.IBEXPCTQTY01 + AVQTY01 AS AVQTYCAL01 , F.IBEXPCTQTY04 + AVQTY04 AS AVQTYCAL04 , F.IBEXPCTQTY05 + AVQTY05 AS AVQTYCAL05 , CASE F.REQCTKEY WHEN '05' THEN F.CTLEADTIME05 WHEN '04' THEN F.CTLEADTIME04 WHEN '01' THEN F.CTLEADTIME01 ELSE F.CTLEADTIME END AS CTLEADTIME_T
FROM ( SELECT IC.ICKEY, IC.ICNM , IC.ASRTYN, IC.ACNM, IC.UNICYN ,IC.CTKEY, IC.OWKEY, IC.DSPYN ,IC.DLVRYYN , IC.SALESTATUS , IC.POABLEYN , IC.NEEDDAYS, IC.LCKEY , IC.SLPRC , /* 상품 정보 */ IC.REQORDERTYPE, IC.ANSUNGB2BPOCTG, IC.NAMSAB2BPOCTG, IC.BUSANB2BPOCTG, IC.CBMCLOSRNG , IC.OBFROMDAY , IC.OBTODAY , IC.OBQTYCRITCAL , IC.APLYDAYS , /* 발주구역 , 통계평균 */ IC.IC_EA, IC.IC_INN , IC.IC_CTN,IC.IC_CPP , IC.VOL, IC.MEASUREMENTYN ,/* 입수량 및 부피 정보 */ COALESCE(AV.QTY, 0) AS DAYQTY , COALESCE(ST.MONTHQTY, 0) AS MONTHQTY, COALESCE(B2BINFO.AVQTY01, 0) AS AVQTY01, COALESCE(B2BINFO.AVQTY04, 0) AS AVQTY04, COALESCE(B2BINFO.AVQTY05, 0) AS AVQTY05, /* B2B재고정보*/ COALESCE(B2BINFO.PREIBQTY01, 0) AS PREIBQTY01, COALESCE(B2BINFO.PREIBQTY04, 0) AS PREIBQTY04, COALESCE(B2BINFO.PREIBQTY05, 0) AS PREIBQTY05, /* B2B 미입고 수량 */ COALESCE(B2BINFO.AVGOBQTY01, 0) AS AVGOBQTY01, COALESCE(B2BINFO.AVGOBQTY04, 0) AS AVGOBQTY04, COALESCE(B2BINFO.AVGOBQTY05, 0) AS AVGOBQTY05, /* B2B 일평균 */ COALESCE(B2BCON.GRTIVDAYS01, 0) AS GRTIVDAYS01, COALESCE(B2BCON.GRTIVDAYS04, 0) AS GRTIVDAYS04, COALESCE(B2BCON.GRTIVDAYS05, 0) AS GRTIVDAYS05, /* B2B 보장일수 */ COALESCE(B2BCON.CTLEADTIME01, 0) AS CTLEADTIME01, COALESCE(B2BCON.CTLEADTIME04, 0) AS CTLEADTIME04, COALESCE(B2BCON.CTLEADTIME05, 0) AS CTLEADTIME05, /* B2B 리드타임*/ COALESCE(B2BCPP.CPP01, 0) AS CPP01, COALESCE(B2BCPP.CPP04, 0) AS CPP04, COALESCE(B2BCPP.CPP05, 0) AS CPP05, /* B2BCPP */ COALESCE(CRITSET.CTNCRIT, 0) AS CTNCRIT, COALESCE(CRITSET.INNCRIT, 0) AS INNCRIT, COALESCE(CRITSET.PLTCRIT, 0) AS PLTCRIT, /* 발주단위 정보 */ COALESCE(MD.REQQTY, 0) AS MDQTY , MD.CMT AS MDCMDT , COALESCE(RIV.AVQTY, 0) AS AVQTY , -- 현재고 COALESCE(IB.B2CIBQTY, 0) AS B2CIBQTY, -- 입고예정정보 -- 미리 계산할 수 있는 항목 정의 -- COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) AS TOTQTY, -- 총재고 ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER (PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) AS TOTQTY, TRUNC(COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_INN, 0),0),2) INNDAYQTY , TRUNC(COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0),2) CTNDAYQTY , TRUNC(COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0) / NULLIF(COALESCE(IC_CPP, 0),0),2) AS PLTDAYQTY, -- 일평균수량 TRUNC(COALESCE(ST.MONTHQTY, 0) / NULLIF(COALESCE(IC_INN, 0),0),2) INNMONTHQTY , TRUNC(COALESCE(ST.MONTHQTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0),2) CTNMONTHQTY , TRUNC(COALESCE(ST.MONTHQTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0) / NULLIF(COALESCE(IC_CPP, 0),0),2) AS PLTMONTHQTY, -- 월평균수량 CASE WHEN B2BINFO.IBEXPCTDAY01 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn}= 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY01, 0) ELSE 0 END AS IBEXPCTQTY01 , CASE WHEN B2BINFO.IBEXPCTDAY04 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY04, 0) ELSE 0 END AS IBEXPCTQTY04 , CASE WHEN B2BINFO.IBEXPCTDAY05 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY05, 0) ELSE 0 END AS IBEXPCTQTY05 , -- 입고 예정정보
ABS( TRUNC(COALESCE(RE.CALAVDAYS, ((COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0)) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER (PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0)) / NULLIF(COALESCE(AV.QTY, 0), 0)),1 ) ) AS NOWCNVRTAVDAYS, /* CASE WHEN TRIM(RE.REQCTKEY) IS NOT NULL THEN RE.REQCTKEY WHEN (COALESCE(B2BINFO.AVQTY05, 0)=0 AND COALESCE(B2BINFO.AVQTY01, 0)=0 AND COALESCE(B2BINFO.AVQTY04, 0)=0) THEN NULL WHEN (COALESCE(B2BINFO.AVQTY05, 0)-COALESCE(B2BINFO.AVGOBQTY05, 0)*COALESCE(B2BCON.GRTIVDAYS05, 0)) >= (COALESCE(AV.QTY, 0)*(3+COALESCE(B2BCON.CTLEADTIME05, 0))) THEN '05'
WHEN (COALESCE(B2BINFO.AVQTY01, 0)-COALESCE(B2BINFO.AVGOBQTY01, 0)*COALESCE(B2BCON.GRTIVDAYS01, 0)) >= (COALESCE(AV.QTY, 0)*(3+COALESCE(B2BCON.CTLEADTIME01, 0))) THEN '01'
WHEN (COALESCE(B2BINFO.AVQTY04, 0)-COALESCE(B2BINFO.AVGOBQTY04, 0)*COALESCE(B2BCON.GRTIVDAYS04, 0)) >= (COALESCE(AV.QTY, 0)*(3+COALESCE(B2BCON.CTLEADTIME04, 0))) THEN '04'
ELSE CASE WHEN COALESCE(B2BINFO.AVQTY05, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY01, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '05' WHEN COALESCE(B2BINFO.AVQTY01, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '01' WHEN COALESCE(B2BINFO.AVQTY04, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY01, 0)) THEN '04' ELSE '05' END END AS REQCTKEY, *//* 발주요청센터 */ CASE /* 강제 지정 */ WHEN TRIM(RE.REQCTKEY) IS NOT NULL THEN RE.REQCTKEY
/* 전 센터 재고 없음 */ WHEN COALESCE(B2BINFO.AVQTY05, 0) = 0 AND COALESCE(B2BINFO.AVQTY01, 0) = 0 AND COALESCE(B2BINFO.AVQTY04, 0) = 0 THEN NULL
/* ========================= 05 센터 ========================= */ WHEN ( COALESCE(B2BINFO.AVQTY05, 0) + CASE WHEN B2BINFO.IBEXPCTDAY05 = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY05, 0) ELSE 0 END - COALESCE(B2BINFO.AVGOBQTY05, 0) * COALESCE(B2BCON.GRTIVDAYS05, 0) ) >= COALESCE(AV.QTY, 0) * GREATEST( COALESCE(IC.NEEDDAYS, 0) + COALESCE(B2BCON.CTLEADTIME05, 0) - ABS( TRUNC( COALESCE(RE.CALAVDAYS, ( ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) ) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER ( PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) / NULLIF(COALESCE(AV.QTY, 0),0)), 1 ) ) , 0 ) THEN '05'
/* ========================= 01 센터 ========================= */ WHEN ( COALESCE(B2BINFO.AVQTY01, 0) + CASE WHEN B2BINFO.IBEXPCTDAY01 = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY01, 0) ELSE 0 END - COALESCE(B2BINFO.AVGOBQTY01, 0) * COALESCE(B2BCON.GRTIVDAYS01, 0) ) >= COALESCE(AV.QTY, 0) * GREATEST( COALESCE(IC.NEEDDAYS, 0) + COALESCE(B2BCON.CTLEADTIME01, 0) - ABS( TRUNC( COALESCE(RE.CALAVDAYS, ( ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) ) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER ( PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) / NULLIF(COALESCE(AV.QTY, 0),0)), 1 ) ) , 0 ) THEN '01'
/* ========================= 04 센터 ========================= */ WHEN ( COALESCE(B2BINFO.AVQTY04, 0) + CASE WHEN B2BINFO.IBEXPCTDAY04 = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY04, 0) ELSE 0 END - COALESCE(B2BINFO.AVGOBQTY04, 0) * COALESCE(B2BCON.GRTIVDAYS04, 0) ) >= COALESCE(AV.QTY, 0) * GREATEST( COALESCE(IC.NEEDDAYS, 0) + COALESCE(B2BCON.CTLEADTIME04, 0) - ABS( TRUNC( COALESCE(RE.CALAVDAYS, ( ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) ) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER ( PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) / NULLIF(COALESCE(AV.QTY, 0),0)), 1 ) ) , 0 ) THEN '04'
/* fallback */ ELSE CASE WHEN COALESCE(B2BINFO.AVQTY05, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY01, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '05' WHEN COALESCE(B2BINFO.AVQTY01, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '01' WHEN COALESCE(B2BINFO.AVQTY04, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY01, 0)) THEN '04' ELSE '05' END END AS REQCTKEY ,
-- RE 커럼 정보 추가 RE.REQORDERDAY, RE.UPLOADYN, RE.REQORDERSTATUS ,COALESCE(RE.SEQ, 1) AS SEQ ,RE.REQORDERUNIT , RE.DLVYREQORDERUNIT , CASE WHEN RE.REQORDERSTATUS NOT IN ( '01','02','03') -- 요청, 확정, 취소 AND COALESCE(RE.RECALCYN, 'N') = 'Y' THEN NULL ELSE RE.REQORDERQTY END AS REQORDERQTY, RE.RECALCYN, COALESCE(RE.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN , RE.AVDAYS AS AVDAYS , -- 발주 가용일 RE.CALAVDAYS AS CALAVDAYS , --환산가용일 RE.CTLEADTIME AS CTLEADTIME , -- 발주요청센터 리드타임 RE.REQORDERAR, RE.INSERTDATE , RE.INSERTURKEY , RE.UPDATEDATE ,RE.UPDATEURKEY FROM ( SELECT A.OWKEY , B.CTKEY , A.ICKEY , A.ICNM , AC.ACNM , A.ASRTYN, A.UNICYN ,A.SLPRC , A.DSPYN ,A.DLVRYYN , A.SALESTATUS , A.POABLEYN , COALESCE(B.NEEDDAYS, 0) AS NEEDDAYS , LC.LCKEY ,LC.ANSUNGB2BPOCTG, LC.NAMSAB2BPOCTG, LC.BUSANB2BPOCTG , LC.CBMCLOSRNG , B.REQORDERTYPE , E.OBFROMDAY , E.OBTODAY , E.OBQTYCRITCAL , E.APLYDAYS , B.IC_EA , B.IC_INN , B.IC_CTN , B.IC_CPP , B.VOL , UT.MEASUREMENTYN FROM TORDER_MST_IC A INNER JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY LEFT JOIN TORDER_MST_ICUTXTYPE UT ON A.OWKEY = UT.OWKEY AND A.ICKEY = UT.ICKEY AND UT.ICUNITTYPE ='EA' LEFT JOIN TORDER_MST_AC AC ON A.OWKEY = AC.OWKEY AND A.ACKEY = AC.ACKEY LEFT JOIN ( SELECT C.OWKEY,C.CTKEY , D.LCKEY ,C.ICKEY, D.ANSUNGB2BPOCTG, D.NAMSAB2BPOCTG, D.BUSANB2BPOCTG , D.CBMCLOSRNG FROM TORDER_MST_ICXCT C LEFT JOIN TORDER_MST_LC D ON C.CTKEY = D.CTKEY AND C.LCKEY = D.LCKEY ) LC ON LC.OWKEY= A.OWKEY AND LC.CTKEY = B.CTKEY AND LC.ICKEY = A.ICKEY LEFT JOIN TORDER_MST_OBAVGQTY E ON A.OWKEY =E.OWKEY AND B.CTKEY = E.CTKEY AND A.ICKEY = E.ICKEY WHERE A.OWKEY = #{owkey} AND B.CTKEY =#{CTKEY} AND B.REQORDERTYPE ='03' AND A.POABLEYN ='Y' AND A.ICSTATUSDIV != '9' AND ( A.ASRTYN = 'N' OR ( A.ASRTYN = 'Y' AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = A.OWKEY AND Z.ASRTREPKEY = A.ICKEY AND Z.QTY > 0 ) ) )
AND A.ICKEY IN
#{item}
AND A.ASRTYN = #{ASRTYN}
AND A.DSPYN = #{DSPYN}
AND A.SALESTATUS = #{SALESTATUS}
AND A.OLNICDIV = #{OLNICDIV}
AND A.DSBTGRADE = #{DSBTGRADE}
) IC LEFT JOIN ( SELECT R.OWKEY , R.CTKEY , COALESCE(Y.ASRTREPKEY, R.ICKEY) AS ICKEY , SUM(R.AVQTY) AS AVQTY FROM ( SELECT A.OWKEY, A.CTKEY, A.ICKEY, SUM(A.AVQTY) AS AVQTY FROM TORDER_INFO_REQORDERIV A JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY AND A.CTKEY = B.CTKEY WHERE A.OWKEY = #{owkey} AND A.CTKEY =#{CTKEY} GROUP BY A.OWKEY, A.CTKEY, A.ICKEY ) R LEFT JOIN TORDER_MST_ASRT Y ON Y.OWKEY = R.OWKEY AND Y.ASRTKEY = R.ICKEY AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = Y.OWKEY AND Z.ASRTREPKEY = Y.ASRTREPKEY AND Z.QTY > 0 ) GROUP BY R.OWKEY, R.CTKEY, COALESCE(Y.ASRTREPKEY, R.ICKEY) ) RIV ON IC.OWKEY = RIV.OWKEY AND IC.CTKEY = RIV.CTKEY AND IC.ICKEY = RIV.ICKEY LEFT JOIN TORDER_INFO_OBSTAT_AVG AV --일평균 출고량 ON IC.OWKEY = AV.OWKEY AND IC.CTKEY = AV.CTKEY AND IC.ICKEY = AV.ICKEY LEFT JOIN ( SELECT A.OWKEY, A.CTKEY, A.ICKEY , DATE_TRUNC('day', SUM(A.QTY) / 30)::DATE AS MONTHQTY FROM TORDER_INFO_ORDER_STAT A JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY WHERE A.OWKEY = #{owkey} AND A.CTKEY =#{CTKEY} AND A.CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '30 days', 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') GROUP BY A.OWKEY, A.CTKEY, A.ICKEY ) ST ON IC.OWKEY = ST.OWKEY AND IC.CTKEY = ST.CTKEY AND IC.ICKEY = ST.ICKEY LEFT JOIN ( SELECT A.ICKEY -- AVQTY 가용재고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY05 -- PREIBQTY 미입고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY05 -- IBEXPCTDAY 입고예정일자 , MAX(CASE WHEN A.CTKEY = '01' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY01 , MAX(CASE WHEN A.CTKEY = '04' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY04 , MAX(CASE WHEN A.CTKEY = '05' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY05 -- IBEXPCTQTY 입고예정수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY05 -- AVGOBQTY 일평균출고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY05 -- B2B 센터재고보장일수
FROM TORDER_INFO_B2BAVGOBQTY_REQORDER A INNER JOIN TORDER_MST_CT B ON A.CTKEY = B.CTKEY JOIN REQ_MST C ON A.ICKEY = C.ICKEY WHERE A.CRITDAY = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND A.AVQTY + A.IBEXPCTDAY > 0 GROUP BY A.ICKEY ) B2BINFO ON IC.ICKEY = B2BINFO.ICKEY LEFT JOIN ( SELECT MAX(CASE WHEN CTKEY = '01' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS05 -- 리드타임 , MAX(CASE WHEN CTKEY = '01' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME05 FROM TORDER_MST_CT ) B2BCON ON 1=1 LEFT JOIN ( SELECT A.ICKEY , COALESCE(MAX(CASE WHEN A.CTKEY = '01' THEN CPP END), 1) AS CPP01 , COALESCE(MAX(CASE WHEN A.CTKEY = '04' THEN CPP END), 1) AS CPP04 , COALESCE(MAX(CASE WHEN A.CTKEY = '05' THEN CPP END), 1) AS CPP05 FROM TORDER_MST_ICXB2BCPP A JOIN REQ_MST B ON A.ICKEY = B.ICKEY GROUP BY A.ICKEY ) B2BCPP ON IC.ICKEY = B2BCPP.ICKEY LEFT JOIN ( SELECT OWKEY , CTKEY , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'CTN' THEN CRITSET END), 0.5) AS CTNCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'PLT' THEN CRITSET END), 0.5) AS PLTCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'INN' THEN CRITSET END), 0.5) AS INNCRIT FROM TORDER_MST_REQORDER_CNTRUNIT WHERE OWKEY = #{owkey} AND CTKEY = #{CTKEY} AND DELYN = 'N' GROUP BY OWKEY, CTKEY ) CRITSET ON IC.OWKEY = CRITSET.OWKEY AND IC.CTKEY = CRITSET.CTKEY LEFT JOIN TORDER_INFO_MD_RDEQODRDER MD ON IC.OWKEY = MD.OWKEY AND IC.CTKEY = MD.CTKEY AND IC.ICKEY = MD.ICKEY AND MD.REQORDERDAY= COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) LEFT JOIN TORDER_INFO_REQORDER RE ON IC.OWKEY = RE.OWKEY AND IC.CTKEY = RE.CTKEY AND IC.ICKEY = RE.ICKEY AND RE.URGENCYREQORDERYN ='N' AND RE.REQORDERDAY= COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) LEFT JOIN ( SELECT H.OWKEY, D.ICKEY, SUM(COALESCE(EXPCTQTY, 0)) AS B2CIBQTY FROM TORDER_INFO_SO_HD H INNER JOIN TORDER_INFO_SO_DT D ON H.OWKEY = D.OWKEY AND H.SOHDKEY = D.SOHDKEY INNER JOIN TORDER_MST_ORTYPE O ON H.OWKEY = O.OWKEY AND H.ORDERTYPECD = O.ORDERTYPECD WHERE O.POCALINCYN = 'Y' AND H.DLVYEXPCTDAY = COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) AND H.OWKEY = #{owkey} AND H.CTKEY = #{CTKEY} GROUP BY H.OWKEY, D.ICKEY )IB ON IC.OWKEY = IB.OWKEY AND IC.ICKEY = IB.ICKEY WHERE 1 = 1 ) F
) S ) T ) X LEFT JOIN TORDER_MST_CT CT ON X.REQCTKEY = CT.CTKEY LEFT JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='POSTATUS' AND INSERTSYSTM = 'OMS' AND LAKEY = 'KOR' ) Y ON X.OWKEY = Y.OWKEY AND Y.COMDTKEY = X.REQORDERSTATUS LEFT JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='REQORDERTYPE' AND INSERTSYSTM = 'OMS' AND LAKEY = 'KOR' ) Z ON X.OWKEY = Z.OWKEY AND Z.COMDTKEY = X.REQORDERTYPE LEFT JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='CD_00203' AND INSERTSYSTM = 'MAL' AND LAKEY = 'KOR' ) ZZ ON X.OWKEY = ZZ.OWKEY AND ZZ.COMDTKEY = X.SALESTATUS WHERE X.OWKEY = #{owkey}
AND ( (X.AVQTY05 + X.IBEXPCTQTY05) > 0 OR (X.AVQTY04 + X.IBEXPCTQTY04) > 0 OR (X.AVQTY01 + X.IBEXPCTQTY01) > 0 )
AND COALESCE(X.NOWCNVRTAVDAYS, 0) > COALESCE(X.AVDAYS_T, 0) AND COALESCE(X.DAYQTY, 0) > 0
AND COALESCE(x.NOWCNVRTAVDAYS, 0) <= COALESCE(X.AVDAYS_T, 0)
AND X.REQORDERSTATUS = #{REQORDERSTATUS}
AND X.REQCTKEY = #{REQCTKEY}
AND COALESCE(X.NOWCNVRTAVDAYS, 0) >= #{CALAVDAYS_FROM}
AND COALESCE(X.NOWCNVRTAVDAYS, 0) <= #{CALAVDAYS_FROM}
AND COALESCE(X.PONEEDDAYS, 0) >= #{PONEEDDAY_FROM}
AND COALESCE(X.PONEEDDAYS, 0) >= #{PONEEDDAY_TO}
AND (CASE WHEN X.REQORDERUNIT IS NOT NULL THEN X.REQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END ) =#{REQORDERUNIT}
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* oms-po-poPlanReq-sql-oracle.xml - selectTOrderPoPlanReqCount */ WITH REQ_MST AS ( SELECT /* hint: MATERIALIZE */ OWKEY ,CTKEY ,ICKEY,REQORDERTYPE ,NEEDDAYS , EAUOM AS IC_EA, INNUOM AS IC_INN, CTNUOM AS IC_CTN, CPPUOM AS IC_CPP , VOL FROM TORDER_MST_REQORDER WHERE OWKEY =#{owkey} AND REQORDERTYPE ='03' AND CTKEY =#{CTKEY}
AND ICKEY IN
#{item}
) SELECT COUNT(1) FROM ( SELECT T.* , CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) END AS PONEEDQTYEA
, CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE ROUND( COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) / NULLIF(COALESCE(T.IC_INN, 1),0), 2) END AS PONEEDQTYINN
, CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE ROUND( COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0), 2) END AS PONEEDQTYCTN , CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE ROUND((COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0)) / NULLIF( COALESCE(T.IC_CTN, 1) * COALESCE(CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END, 0) , 0) , 2) END AS PONEEDQTYPLT /*싱글*/ , 0 AS CAND_QTY_INN , CASE /* 카톤 기준 환산 후 올림 */ WHEN CEIL( COALESCE(T.REQQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN CEIL( COALESCE(T.REQQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) /* 초과 시: 센터반영치 내에서 카톤 단위로 절사 */ ELSE FLOOR( COALESCE(T.B2BCARDBASEQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) END AS CAND_QTY_CTN , CASE WHEN T.CTNCRIT IS NULL THEN 0 WHEN ( T.REQQTY / NULLIF( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END , 0) ) >= T.CTNCRIT THEN LEAST( /* PLT 올림 후 수량 환산 */ CEIL( T.REQQTY / NULLIF( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END , 0) ) * ( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END ), /* 카드 기준 초과 방어 */ COALESCE(T.B2BCARDBASEQTY, 0) ) ELSE 0 END AS CAND_QTY_PLT
/*멀티*/ , CASE WHEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0) + (1 - COALESCE(T.INNCRIT, 0.5))) * COALESCE(T.IC_INN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0) + (1 - COALESCE(T.INNCRIT, 0.5))) * COALESCE(T.IC_INN, 1) ELSE FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0)) * COALESCE(T.IC_INN, 1) END AS CAND_QTY_INN , CASE WHEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0) + (1-COALESCE(T.CTNCRIT, 0.5))) * COALESCE(T.IC_CTN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0) + (1-COALESCE(T.CTNCRIT, 0.5))) * COALESCE(T.IC_CTN, 1) ELSE FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0)) * COALESCE(T.IC_CTN, 1) END AS CAND_QTY_CTN , CASE WHEN COALESCE(T.IC_CTN, 0)=0 THEN NULL WHEN COALESCE(CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END, 0)=0 THEN NULL ELSE CASE WHEN FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) + (1-COALESCE(T.PLTCRIT, 0.5)) ) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) + (1-COALESCE(T.PLTCRIT, 0.5)) ) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) ELSE FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0))) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) END END AS CAND_QTY_PLT
FROM (
SELECT S.* /* 센터재고 반영 필요 발주량 : 필요발주량 – (B2B재고수량 – (보장재고일수 * 오프라인일 평균수량 )) 각센터별 센터재고 반영 필요 발주량 */ , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0))) END AS REQQTY01 , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0))) END AS REQQTY04 , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0))) END AS REQQTY05 , CASE WHEN (CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) ELSE 0 END) <= 0 THEN 0 ELSE LEAST( GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) /* B2B재고수량 - B2B보장재고 */ WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) ELSE 0 END ) END AS REQQTY /* 발주요청센터 반영 필요 발주량 해당수량 정보를 읽어서 발주 단위를 구한다. */ , GREATEST( 0, CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) /* 안성 */ WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) /* 부산 */ WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) /* 남사 */ ELSE 0 END ) AS B2BCARDBASEQTY
FROM ( SELECT F.* /* 발주 필요 가능일 : (가용일 + 센터 리드타임) - 현재 환산 가용일 [현재 환산가용일 : 총재고 / 일평균수량] */ , CASE WHEN F.CALAVDAYS IS NOT NULL THEN F.AVDAYS + F.CTLEADTIME - F.CALAVDAYS ELSE (CASE F.REQCTKEY WHEN '05' THEN F.CTLEADTIME05 + F.NEEDDAYS - F.NOWCNVRTAVDAYS WHEN '04' THEN F.CTLEADTIME04 + F.NEEDDAYS - F.NOWCNVRTAVDAYS WHEN '01' THEN F.CTLEADTIME01 + F.NEEDDAYS - F.NOWCNVRTAVDAYS ELSE 0 END) END AS PONEEDDAYS , COALESCE(F.AVDAYS, F.NEEDDAYS) AS AVDAYS_T /* B2B보장재고 */ , F.GRTIVDAYS01 * F.AVGOBQTY01 AS CTGRTQTY01 , F.GRTIVDAYS04 * F.AVGOBQTY04 AS CTGRTQTY04 , F.GRTIVDAYS05 * F.AVGOBQTY05 AS CTGRTQTY05 /* B2B센터 재고 + B2B입고예정정보 : B2B재고수량 */ , F.IBEXPCTQTY01 + AVQTY01 AS AVQTYCAL01 , F.IBEXPCTQTY04 + AVQTY04 AS AVQTYCAL04 , F.IBEXPCTQTY05 + AVQTY05 AS AVQTYCAL05 , CASE F.REQCTKEY WHEN '05' THEN F.CTLEADTIME05 WHEN '04' THEN F.CTLEADTIME04 WHEN '01' THEN F.CTLEADTIME01 ELSE F.CTLEADTIME END AS CTLEADTIME_T
FROM ( SELECT IC.ICKEY, IC.ICNM , IC.ASRTYN, IC.UNICYN ,IC.CTKEY, IC.OWKEY, IC.DSPYN ,IC.DLVRYYN , IC.SALESTATUS , IC.POABLEYN , IC.NEEDDAYS, IC.SLPRC , /* 상품 정보 */ IC.REQORDERTYPE, IC.OBFROMDAY , IC.OBTODAY , IC.OBQTYCRITCAL , IC.APLYDAYS ,/* 발주구역 , 통계평균 */ IC.IC_EA, IC.IC_INN , IC.IC_CTN,IC.IC_CPP , IC.VOL, /* 입수량 및 부피 정보 */ COALESCE(AV.QTY, 0) AS DAYQTY , COALESCE(B2BINFO.AVQTY01, 0) AS AVQTY01, COALESCE(B2BINFO.AVQTY04, 0) AS AVQTY04, COALESCE(B2BINFO.AVQTY05, 0) AS AVQTY05, /* B2B재고정보*/ COALESCE(B2BINFO.PREIBQTY01, 0) AS PREIBQTY01, COALESCE(B2BINFO.PREIBQTY04, 0) AS PREIBQTY04, COALESCE(B2BINFO.PREIBQTY05, 0) AS PREIBQTY05, /* B2B 미입고 수량 */ COALESCE(B2BINFO.AVGOBQTY01, 0) AS AVGOBQTY01, COALESCE(B2BINFO.AVGOBQTY04, 0) AS AVGOBQTY04, COALESCE(B2BINFO.AVGOBQTY05, 0) AS AVGOBQTY05, /* B2B 일평균 */ COALESCE(B2BCON.GRTIVDAYS01, 0) AS GRTIVDAYS01, COALESCE(B2BCON.GRTIVDAYS04, 0) AS GRTIVDAYS04, COALESCE(B2BCON.GRTIVDAYS05, 0) AS GRTIVDAYS05, /* B2B 보장일수 */ COALESCE(B2BCON.CTLEADTIME01, 0) AS CTLEADTIME01, COALESCE(B2BCON.CTLEADTIME04, 0) AS CTLEADTIME04, COALESCE(B2BCON.CTLEADTIME05, 0) AS CTLEADTIME05, /* B2B 리드타임*/ COALESCE(B2BCPP.CPP01, 0) AS CPP01, COALESCE(B2BCPP.CPP04, 0) AS CPP04, COALESCE(B2BCPP.CPP05, 0) AS CPP05, /* B2BCPP */ COALESCE(CRITSET.CTNCRIT, 0) AS CTNCRIT, COALESCE(CRITSET.INNCRIT, 0) AS INNCRIT, COALESCE(CRITSET.PLTCRIT, 0) AS PLTCRIT, /* 발주단위 정보 */ COALESCE(MD.REQQTY, 0) AS MDQTY , MD.CMT AS MDCMDT , COALESCE(RIV.AVQTY, 0) AS AVQTY , -- 현재고 COALESCE(IB.B2CIBQTY, 0) AS B2CIBQTY, -- 입고예정정보 -- 미리 계산할 수 있는 항목 정의 ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER (PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) AS TOTQTY, DATE_TRUNC('day', COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_INN, 0),0))::DATE INNDAYQTY , DATE_TRUNC('day', COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0))::DATE CTNDAYQTY , DATE_TRUNC('day', COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0) / NULLIF(COALESCE(IC_CPP, 0),0))::DATE AS PLTDAYQTY, -- 일평균수량 CASE WHEN B2BINFO.IBEXPCTDAY01 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn}= 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY01, 0) ELSE 0 END AS IBEXPCTQTY01 , CASE WHEN B2BINFO.IBEXPCTDAY04 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY04, 0) ELSE 0 END AS IBEXPCTQTY04 , CASE WHEN B2BINFO.IBEXPCTDAY05 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY05, 0) ELSE 0 END AS IBEXPCTQTY05 , -- 입고 예정정보 ABS( ROUND(COALESCE(RE.CALAVDAYS, ((COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0)) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER (PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0)) / NULLIF(COALESCE(AV.QTY, 0), 0)),1 ) ) AS NOWCNVRTAVDAYS, CASE /* 강제 지정 */ WHEN TRIM(RE.REQCTKEY) IS NOT NULL THEN RE.REQCTKEY
/* 전 센터 재고 없음 */ WHEN COALESCE(B2BINFO.AVQTY05, 0) = 0 AND COALESCE(B2BINFO.AVQTY01, 0) = 0 AND COALESCE(B2BINFO.AVQTY04, 0) = 0 THEN NULL
/* ========================= 05 센터 ========================= */ WHEN ( COALESCE(B2BINFO.AVQTY05, 0) + CASE WHEN B2BINFO.IBEXPCTDAY05 = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY05, 0) ELSE 0 END - COALESCE(B2BINFO.AVGOBQTY05, 0) * COALESCE(B2BCON.GRTIVDAYS05, 0) ) >= COALESCE(AV.QTY, 0) * GREATEST( COALESCE(IC.NEEDDAYS, 0) + COALESCE(B2BCON.CTLEADTIME05, 0) - ABS( TRUNC( COALESCE(RE.CALAVDAYS, ( ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) ) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER ( PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) / NULLIF(COALESCE(AV.QTY, 0),0)), 1 ) ) , 0 ) THEN '05'
/* ========================= 01 센터 ========================= */ WHEN ( COALESCE(B2BINFO.AVQTY01, 0) + CASE WHEN B2BINFO.IBEXPCTDAY01 = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY01, 0) ELSE 0 END - COALESCE(B2BINFO.AVGOBQTY01, 0) * COALESCE(B2BCON.GRTIVDAYS01, 0) ) >= COALESCE(AV.QTY, 0) * GREATEST( COALESCE(IC.NEEDDAYS, 0) + COALESCE(B2BCON.CTLEADTIME01, 0) - ABS( TRUNC( COALESCE(RE.CALAVDAYS, ( ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) ) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER ( PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) / NULLIF(COALESCE(AV.QTY, 0),0)), 1 ) ) , 0 ) THEN '01'
/* ========================= 04 센터 ========================= */ WHEN ( COALESCE(B2BINFO.AVQTY04, 0) + CASE WHEN B2BINFO.IBEXPCTDAY04 = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY04, 0) ELSE 0 END - COALESCE(B2BINFO.AVGOBQTY04, 0) * COALESCE(B2BCON.GRTIVDAYS04, 0) ) >= COALESCE(AV.QTY, 0) * GREATEST( COALESCE(IC.NEEDDAYS, 0) + COALESCE(B2BCON.CTLEADTIME04, 0) - ABS( TRUNC( COALESCE(RE.CALAVDAYS, ( ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) ) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER ( PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) / NULLIF(COALESCE(AV.QTY, 0),0)), 1 ) ) , 0 ) THEN '04'
/* fallback */ ELSE CASE WHEN COALESCE(B2BINFO.AVQTY05, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY01, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '05' WHEN COALESCE(B2BINFO.AVQTY01, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '01' WHEN COALESCE(B2BINFO.AVQTY04, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY01, 0)) THEN '04' ELSE '05' END END AS REQCTKEY ,
-- RE 커럼 정보 추가 RE.REQORDERDAY, RE.UPLOADYN, RE.REQORDERSTATUS ,COALESCE(RE.SEQ, 1) AS SEQ ,RE.REQORDERUNIT , RE.DLVYREQORDERUNIT , CASE WHEN RE.REQORDERSTATUS NOT IN ( '01','02','03') -- 요청, 확정, 취소 AND COALESCE(RE.RECALCYN, 'N') = 'Y' THEN NULL ELSE RE.REQORDERQTY END AS REQORDERQTY, RE.RECALCYN, COALESCE(RE.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN , RE.AVDAYS AS AVDAYS , -- 발주 가용일 RE.CALAVDAYS AS CALAVDAYS , --환산가용일 RE.CTLEADTIME AS CTLEADTIME , -- 발주요청센터 리드타임 RE.INSERTDATE , RE.INSERTURKEY , RE.UPDATEDATE ,RE.UPDATEURKEY FROM ( SELECT A.OWKEY , B.CTKEY , A.ICKEY, A.ICNM , A.ASRTYN, A.UNICYN ,A.SLPRC , A.DSPYN ,A.DLVRYYN , A.SALESTATUS , A.POABLEYN , COALESCE(B.NEEDDAYS, 0) AS NEEDDAYS , B.REQORDERTYPE , E.OBFROMDAY , E.OBTODAY , E.OBQTYCRITCAL , E.APLYDAYS , B.IC_EA , B.IC_INN , B.IC_CTN , B.IC_CPP , B.VOL FROM TORDER_MST_IC A INNER JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY LEFT JOIN TORDER_MST_OBAVGQTY E ON A.OWKEY =E.OWKEY AND B.CTKEY = E.CTKEY AND A.ICKEY = E.ICKEY WHERE A.OWKEY = #{owkey} AND B.CTKEY =#{CTKEY} AND B.REQORDERTYPE ='03' AND A.POABLEYN ='Y' AND A.ICSTATUSDIV != '9' AND ( A.ASRTYN = 'N' OR ( A.ASRTYN = 'Y' AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = A.OWKEY AND Z.ASRTREPKEY = A.ICKEY AND Z.QTY > 0 ) ) )
AND A.ICKEY IN
#{item}
AND A.ASRTYN = #{ASRTYN}
AND A.DSPYN = #{DSPYN}
AND A.SALESTATUS = #{SALESTATUS}
AND A.OLNICDIV = #{OLNICDIV}
AND A.DSBTGRADE = #{DSBTGRADE}
) IC -- JOIN ICXUT UT -- ON UT.OWKEY = IC.OWKEY -- AND UT.ICKEY = IC.ICKEY LEFT JOIN ( SELECT R.OWKEY , R.CTKEY , COALESCE(Y.ASRTREPKEY, R.ICKEY) AS ICKEY , SUM(R.AVQTY) AS AVQTY FROM ( SELECT A.OWKEY, A.CTKEY, A.ICKEY, SUM(A.AVQTY) AS AVQTY FROM TORDER_INFO_REQORDERIV A JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY AND A.CTKEY = B.CTKEY WHERE A.OWKEY = #{owkey} AND A.CTKEY =#{CTKEY} GROUP BY A.OWKEY, A.CTKEY, A.ICKEY ) R LEFT JOIN TORDER_MST_ASRT Y ON Y.OWKEY = R.OWKEY AND Y.ASRTKEY = R.ICKEY AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = Y.OWKEY AND Z.ASRTREPKEY = Y.ASRTREPKEY AND Z.QTY > 0 ) GROUP BY R.OWKEY, R.CTKEY, COALESCE(Y.ASRTREPKEY, R.ICKEY) ) RIV ON IC.OWKEY = RIV.OWKEY AND IC.CTKEY = RIV.CTKEY AND IC.ICKEY = RIV.ICKEY LEFT JOIN TORDER_INFO_OBSTAT_AVG AV --일평균 출고량 ON IC.OWKEY = AV.OWKEY AND IC.CTKEY = AV.CTKEY AND IC.ICKEY = AV.ICKEY LEFT JOIN ( SELECT A.ICKEY -- AVQTY 가용재고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY05 -- PREIBQTY 미입고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY05 -- IBEXPCTDAY 입고예정일자 , MAX(CASE WHEN A.CTKEY = '01' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY01 , MAX(CASE WHEN A.CTKEY = '04' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY04 , MAX(CASE WHEN A.CTKEY = '05' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY05 -- IBEXPCTQTY 입고예정수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY05 -- AVGOBQTY 일평균출고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY05 -- B2B 센터재고보장일수
FROM TORDER_INFO_B2BAVGOBQTY_REQORDER A INNER JOIN TORDER_MST_CT B ON A.CTKEY = B.CTKEY JOIN REQ_MST C ON A.ICKEY = C.ICKEY WHERE A.CRITDAY = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND A.AVQTY + A.IBEXPCTDAY > 0 GROUP BY A.ICKEY ) B2BINFO ON IC.ICKEY = B2BINFO.ICKEY LEFT JOIN ( SELECT MAX(CASE WHEN CTKEY = '01' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS05 -- 리드타임 , MAX(CASE WHEN CTKEY = '01' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME05 FROM TORDER_MST_CT ) B2BCON ON 1=1 LEFT JOIN ( SELECT A.ICKEY , COALESCE(MAX(CASE WHEN A.CTKEY = '01' THEN CPP END), 1) AS CPP01 , COALESCE(MAX(CASE WHEN A.CTKEY = '04' THEN CPP END), 1) AS CPP04 , COALESCE(MAX(CASE WHEN A.CTKEY = '05' THEN CPP END), 1) AS CPP05 FROM TORDER_MST_ICXB2BCPP A JOIN REQ_MST B ON A.ICKEY = B.ICKEY GROUP BY A.ICKEY ) B2BCPP ON IC.ICKEY = B2BCPP.ICKEY LEFT JOIN ( SELECT OWKEY , CTKEY , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'CTN' THEN CRITSET END), 0.5) AS CTNCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'PLT' THEN CRITSET END), 0.5) AS PLTCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'INN' THEN CRITSET END), 0.5) AS INNCRIT FROM TORDER_MST_REQORDER_CNTRUNIT WHERE OWKEY =#{owkey} AND CTKEY =#{CTKEY} AND DELYN ='N' GROUP BY OWKEY, CTKEY ) CRITSET ON IC.OWKEY = CRITSET.OWKEY AND IC.CTKEY = CRITSET.CTKEY LEFT JOIN TORDER_INFO_MD_RDEQODRDER MD ON IC.OWKEY = MD.OWKEY AND IC.CTKEY = MD.CTKEY AND IC.ICKEY = MD.ICKEY AND MD.REQORDERDAY= COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) LEFT JOIN TORDER_INFO_REQORDER RE ON IC.OWKEY = RE.OWKEY AND IC.CTKEY = RE.CTKEY AND IC.ICKEY = RE.ICKEY AND RE.REQORDERDAY= COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) AND RE.URGENCYREQORDERYN ='N' LEFT JOIN ( SELECT H.OWKEY, D.ICKEY, SUM(COALESCE(EXPCTQTY, 0)) AS B2CIBQTY FROM TORDER_INFO_SO_HD H INNER JOIN TORDER_INFO_SO_DT D ON H.OWKEY = D.OWKEY AND H.SOHDKEY = D.SOHDKEY INNER JOIN TORDER_MST_ORTYPE O ON H.OWKEY = O.OWKEY AND H.ORDERTYPECD = O.ORDERTYPECD WHERE O.POCALINCYN = 'Y' AND H.DLVYEXPCTDAY = COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) AND H.OWKEY = #{owkey} AND H.CTKEY = #{CTKEY} GROUP BY H.OWKEY, D.ICKEY )IB ON IC.OWKEY = IB.OWKEY AND IC.ICKEY = IB.ICKEY WHERE 1 = 1 ) F
) S ) T ) X WHERE X.OWKEY = #{owkey}
AND ( (X.AVQTY05 + X.IBEXPCTQTY05) > 0 OR (X.AVQTY04 + X.IBEXPCTQTY04) > 0 OR (X.AVQTY01 + X.IBEXPCTQTY01) > 0 )
AND COALESCE(X.NOWCNVRTAVDAYS, 0) > COALESCE(X.AVDAYS_T, 0) AND COALESCE(X.DAYQTY, 0) > 0
AND COALESCE(x.NOWCNVRTAVDAYS, 0) <= COALESCE(X.AVDAYS_T, 0)
AND X.REQORDERSTATUS = #{REQORDERSTATUS}
AND X.REQCTKEY = #{REQCTKEY}
AND COALESCE(X.NOWCNVRTAVDAYS, 0) >= #{CALAVDAYS_FROM}
AND COALESCE(X.NOWCNVRTAVDAYS, 0) <= #{CALAVDAYS_FROM}
AND COALESCE(X.PONEEDDAYS, 0) >= #{PONEEDDAY_FROM}
AND COALESCE(X.PONEEDDAYS, 0) >= #{PONEEDDAY_TO}
AND (CASE WHEN X.REQORDERUNIT IS NOT NULL THEN X.REQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END ) =#{REQORDERUNIT}

WITH REQ_MST AS ( SELECT /* hint: MATERIALIZE */ OWKEY ,CTKEY ,ICKEY,REQORDERTYPE ,NEEDDAYS , EAUOM AS IC_EA, INNUOM AS IC_INN, CTNUOM AS IC_CTN, CPPUOM AS IC_CPP , VOL FROM TORDER_MST_REQORDER WHERE OWKEY =#{owkey} AND REQORDERTYPE ='03' AND CTKEY =#{CTKEY}
AND ICKEY IN
#{item}
) SELECT '0' AS CHK, X.REQCTKEY, CT.CTNM AS REQCTNM, COALESCE(X.REQORDERDAY, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')) AS REQORDERDAY, 'N' AS URGENCYREQORDERYN, COALESCE(X.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN, CASE WHEN X.UPLOADYN = 'Y' THEN '업로드' ELSE '자동' END AS UPLOADYN , /* 센터재고 반영 필요 발주량 (개/중포/카톤/팔레트) */ X.REQQTY AS IVRFLCTNEEDQTYEA, TRUNC( COALESCE(X.REQQTY, 0) / NULLIF(COALESCE(X.IC_INN, 1),0) , 2) AS IVRFLCTNEEDQTYINN, TRUNC( COALESCE(X.REQQTY, 0) / NULLIF(COALESCE(X.IC_CTN, 1),0) , 2) AS IVRFLCTNEEDQTYCTN, TRUNC(COALESCE(X.REQQTY, 0)/ NULLIF(COALESCE(X.IC_CTN, 1) * NULLIF(CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE NULL END,0), 0) , 2) AS IVRFLCTNEEDQTYPLT,
/* 발주구역/타겟 */ CASE WHEN X.REQORDERAR IS NOT NULL THEN X.REQORDERAR WHEN X.MEASUREMENTYN ='N' THEN 'N' WHEN X.ASRTYN ='Y' THEN 'T' WHEN X.REQCTKEY ='05'THEN X.ANSUNGB2BPOCTG WHEN X.REQCTKEY ='04'THEN X.BUSANB2BPOCTG WHEN X.REQCTKEY ='01'THEN X.NAMSAB2BPOCTG ELSE '' END AS REQORDERAR, X.ANSUNGB2BPOCTG, X.BUSANB2BPOCTG, X.NAMSAB2BPOCTG, X.LCKEY AS ICTGT, /* 상태/유형 */ COALESCE(X.REQORDERSTATUS, '') AS REQORDERSTATUS, Y.COMDTNM AS REQORDERSTATUSNM, COALESCE(X.REQORDERTYPE, '03') AS REQORDERTYPE , -- 03 : 이고발주 Z.COMDTNM AS REQORDERTYPENM, /* 키/식별자 */ COALESCE(X.SEQ, 0) AS SEQ, COALESCE(X.OWKEY, '') AS OWKEY, COALESCE(X.CTKEY, '') AS CTKEY, /* 상품정보 */ COALESCE(X.ICKEY, '') AS ICKEY, COALESCE(X.ICNM, '') AS ICNM, COALESCE(X.ASRTYN, '') AS ASRTYN, COALESCE(X.IC_EA, 0) AS ICEA, COALESCE(X.IC_INN, 0) AS ICINN, COALESCE(X.IC_CTN, 0) AS ICCTN, COALESCE(X.IC_CPP, 0) AS ICCPP, /* 상품상태 */ COALESCE(X.UNICYN, '') AS UNICYN, COALESCE(X.DSPYN, '') AS DSPYN, COALESCE(X.DLVRYYN, '') AS DLVRYYN, /*COALESCE(X.SALESTATUS, '') AS SALESTATUS, */ ZZ.COMDTNM AS SALESTATUS, COALESCE(X.POABLEYN, '') AS ABLEREQORDERYN, COALESCE(X.ACNM, '') AS ACNM, /* 일/월평균 출고량 */ COALESCE(X.DAYQTY, 0) AS EADAYAVGOBQTY, TO_CHAR( COALESCE(X.INNDAYQTY, 0) ,'FM999,999,990.00') AS INNDAYAVGOBQTY, TO_CHAR( COALESCE(X.CTNDAYQTY, 0) ,'FM999,999,990.00') AS CTNDAYAVGOBQTY, TO_CHAR( COALESCE(X.PLTDAYQTY, 0) ,'FM999,999,990.00') AS PLTDAYAVGOBQTY, COALESCE(X.MONTHQTY, 0) AS EAMONTHAVGOBQTY, COALESCE(X.INNMONTHQTY, 0) AS INNMONTHAVGOBQTY, COALESCE(X.CTNMONTHQTY, 0) AS CTNMONTHAVGOBQTY, COALESCE(X.PLTMONTHQTY, 0) AS PLTMONTHAVGOBQTY, /* B2B 센터 입고예정 */ COALESCE(X.IBEXPCTQTY01, 0) AS NAMSAIBEXPCTQTY, COALESCE(X.IBEXPCTQTY04, 0) AS BUSANIBEXPCTQTY, COALESCE(X.IBEXPCTQTY05, 0) AS ANSUNGIBEXPCTQTY, /* B2B 센터 재고 */ COALESCE(X.AVQTY01, 0) AS NAMSAAVQTY, COALESCE(X.AVQTY04, 0) AS BUSANAVQTY, COALESCE(X.AVQTY05, 0) AS ANSUNGAVQTY, /* B2B 일평균 */ COALESCE(X.AVGOBQTY01, 0) AS NAMSAAVGOBQTY, COALESCE(X.AVGOBQTY04, 0) AS BUSANAVGOBQTY, COALESCE(X.AVGOBQTY05, 0) AS ANSUNGAVGOBQTY, /* B2B 보장재고(일수*일평균) */ COALESCE(X.GRTIVDAYS01 * X.AVGOBQTY01, 0) AS NAMSAB2BCTGRTQTY, COALESCE(X.GRTIVDAYS04 * X.AVGOBQTY04, 0) AS BUSANB2BCTGRTQTY, COALESCE(X.GRTIVDAYS05 * X.AVGOBQTY05, 0) AS ANSUNGB2BCTGRTQTY, /* 온라인 재고/총재고/환산가용일 */ COALESCE(X.AVQTY, 0) AS AVQTY, COALESCE(X.B2CIBQTY, 0) AS B2CIBQTY, '' AS B2CIBYN, COALESCE(X.TOTQTY, 0) AS TOTQTY, TO_CHAR( COALESCE(X.NOWCNVRTAVDAYS, 0) ,'FM999,999,990.0') AS CALAVDAYS, /* 가용일/리드타임/발주 필요 가능일 */ COALESCE(X.CTLEADTIME_T, 0) AS CTLEADTIME, COALESCE(X.AVDAYS_T, 0) AS AVDAYS,TO_CHAR( COALESCE(X.PONEEDDAYS, 0) ,'FM999,999,990.0') AS PONEEDDAYS, /* MD 요청 */ COALESCE(X.MDQTY, 0) AS MDREQQTY, COALESCE(X.MDCMDT, '') AS MDCMT, CASE WHEN X.REQORDERUNIT IS NOT NULL THEN X.REQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END AS REQORDERUNIT, CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END AS REQORDERQTY , CASE WHEN X.REQORDERUNIT IS NOT NULL THEN X.REQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END AS DLVYREQORDERUNIT, /* 파생: PLT/CTN/INN 환산 수량 */ TO_CHAR( TRUNC((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END ) / NULLIF( COALESCE(X.IC_CTN, 1) * COALESCE(CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END, 1) ,0) ,2) , 'FM999,999,990.00') AS REQORDERPLT, TO_CHAR(TRUNC((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END) / NULLIF(COALESCE(X.IC_CTN, 1),0) ,2) , 'FM999,999,990.00') AS REQORDERCTN ,
TO_CHAR( TRUNC((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END) / NULLIF(COALESCE(X.IC_INN, 1),0) ,2) , 'FM999,999,990.00') AS REQORDERINN , TO_CHAR(CEIL(COALESCE((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END), 0) * COALESCE(X.VOL, 0) * 100 ) / 100 , 'FM999,999,990.00') AS REQCBM, CEIL(COALESCE((CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END), 0) * COALESCE(X.SLPRC, 0) * 100) / 100 AS REQPRC , CASE WHEN CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END > X.B2BCARDBASEQTY THEN 'Excess Order Allowed' ELSE '' END AS CMT , X.CTNCRIT , X.PLTCRIT , X.INNCRIT , COALESCE(X.CPP01, '') AS NAMSACPP, COALESCE(X.CPP04, '') AS BUSANCPP, COALESCE(X.CPP05, '') AS ANSUNGCPP, CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END AS CPP , /* 부피/가격 원천 */ COALESCE(X.VOL, '') AS VOL, COALESCE(X.SLPRC, '') AS SLPRC, /* 예정가용일: (현 재고 - 일평균*리드타임 + 발주요청수량) / 일평균 */ TO_CHAR(TRUNC(( COALESCE(X.TOTQTY, 0) - (CASE COALESCE(X.DAYQTY, 0) WHEN 0 THEN 1 ELSE X.DAYQTY END * COALESCE(X.CTLEADTIME_T, 1)) + (CASE WHEN X.REQORDERQTY IS NOT NULL THEN X.REQORDERQTY ELSE CASE WHEN COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_CTN, 0) AND COALESCE(X.CAND_QTY_PLT, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_PLT, 0) WHEN COALESCE(X.CAND_QTY_CTN, 0) >= COALESCE(X.CAND_QTY_INN, 0) THEN COALESCE(X.CAND_QTY_CTN, 0) ELSE COALESCE(X.CAND_QTY_INN, 0) END END) ) / CASE COALESCE(X.DAYQTY, 0) WHEN 0 THEN 1 ELSE X.DAYQTY END,1), 'FM999,999,990.0') AS EXPCTAVDAYS, /* 평균 집계 기간 */ X.OBFROMDAY AS AVGOBFROMDAY, X.OBTODAY AS AVGOBTODAY, X.APLYDAYS AS AVGAPLYDAYS, /* 센터별 리드타임 */ X.CTLEADTIME05, X.CTLEADTIME04, X.CTLEADTIME01, /* 필요 발주량*/ X.PONEEDQTYEA, TO_CHAR(X.PONEEDQTYINN ,'FM999,999,990.00') PONEEDQTYINN, TO_CHAR(X.PONEEDQTYCTN ,'FM999,999,990.00') PONEEDQTYCTN, TO_CHAR(CASE X.REQCTKEY WHEN '01' THEN TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.CPP01, 1),0), 2) WHEN '04' THEN TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.CPP04, 1),0), 2) WHEN '05' THEN TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.CPP05, 1),0), 2) ELSE TRUNC(COALESCE(X.PONEEDQTYCTN, 0) / NULLIF(COALESCE(X.IC_CPP, 1),0), 2) END ,'FM999,999,990.00') AS PONEEDQTYPLT , X.RECALCYN, X.CBMCLOSRNG, /* 감사 컬럼 */ COALESCE(X.INSERTDATE, '') AS INSERTDATE, COALESCE(X.INSERTURKEY, '') AS INSERTURKEY, COALESCE(X.UPDATEDATE, '') AS UPDATEDATE, COALESCE(X.UPDATEURKEY, '') AS UPDATEURKEY FROM ( SELECT T.* , CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) END AS PONEEDQTYEA
, CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE TRUNC( COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) / NULLIF(COALESCE(T.IC_INN, 1),0), 2) END AS PONEEDQTYINN
, CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE TRUNC( COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0), 2) END AS PONEEDQTYCTN , CASE WHEN COALESCE(T.PONEEDDAYS, 0) < 0 THEN 0 ELSE TRUNC((COALESCE(T.PONEEDDAYS, 0) * COALESCE(T.DAYQTY, 0)) / NULLIF( COALESCE(T.IC_CTN, 1) * COALESCE(CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END, 0) , 0) , 2) END AS PONEEDQTYPLT /*싱글*/ , 0 AS CAND_QTY_INN , CASE /* 카톤 기준 환산 후 올림 */ WHEN CEIL( COALESCE(T.REQQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN CEIL( COALESCE(T.REQQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) /* 초과 시: 센터반영치 내에서 카톤 단위로 절사 */ ELSE FLOOR( COALESCE(T.B2BCARDBASEQTY, 0) / NULLIF(COALESCE(T.IC_CTN, 1),0) ) * COALESCE(T.IC_CTN, 1) END AS CAND_QTY_CTN , CASE WHEN T.CTNCRIT IS NULL THEN 0 WHEN ( CEIL( T.REQQTY / COALESCE(T.IC_CTN, 1) ) * COALESCE(T.IC_CTN, 1) / NULLIF( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END , 0) ) >= T.CTNCRIT THEN LEAST( /* PLT 올림 후 수량 환산 */ CEIL( T.REQQTY / NULLIF( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END , 0) ) * ( COALESCE(T.IC_CTN, 1) * CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END ), /* 카드 기준 초과 방어 */ COALESCE(T.B2BCARDBASEQTY, 0) ) ELSE 0 END AS CAND_QTY_PLT
/*멀티*/ , CASE WHEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0) + (1 - COALESCE(T.INNCRIT, 0.5))) * COALESCE(T.IC_INN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0) + (1 - COALESCE(T.INNCRIT, 0.5))) * COALESCE(T.IC_INN, 1) ELSE FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_INN, 1),0)) * COALESCE(T.IC_INN, 1) END AS CAND_QTY_INN , CASE WHEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0) + (1-COALESCE(T.CTNCRIT, 0.5))) * COALESCE(T.IC_CTN, 1) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0) + (1-COALESCE(T.CTNCRIT, 0.5))) * COALESCE(T.IC_CTN, 1) ELSE FLOOR(COALESCE(T.REQQTY, 0)/NULLIF(COALESCE(T.IC_CTN, 1),0)) * COALESCE(T.IC_CTN, 1) END AS CAND_QTY_CTN , CASE WHEN COALESCE(T.IC_CTN, 0)=0 THEN NULL WHEN COALESCE(CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END, 0)=0 THEN NULL ELSE CASE WHEN FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) + (1-COALESCE(T.PLTCRIT, 0.5)) ) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) <= COALESCE(T.B2BCARDBASEQTY, 0) THEN FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) + (1-COALESCE(T.PLTCRIT, 0.5)) ) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) ELSE FLOOR( COALESCE(T.REQQTY, 0)/(T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0))) * (T.IC_CTN*NULLIF( CASE T.REQCTKEY WHEN '01' THEN T.CPP01 WHEN '04' THEN T.CPP04 WHEN '05' THEN T.CPP05 END,0)) END END AS CAND_QTY_PLT
FROM (
SELECT S.* /* 센터재고 반영 필요 발주량 : 필요발주량 – (B2B재고수량 – (보장재고일수 * 오프라인일 평균수량 )) 각센터별 센터재고 반영 필요 발주량 */ , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0))) END AS REQQTY01 , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0))) END AS REQQTY04 , CASE WHEN GREATEST(0, COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0)) <= 0 THEN 0 ELSE LEAST(GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), GREATEST(0, COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0))) END AS REQQTY05 , CASE WHEN (CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) ELSE 0 END) <= 0 THEN 0 ELSE LEAST( GREATEST(0, COALESCE(S.PONEEDDAYS, 0) * COALESCE(S.DAYQTY, 0)), CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) - COALESCE(S.CTGRTQTY05, 0) /* B2B재고수량 - B2B보장재고 */ WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) - COALESCE(S.CTGRTQTY04, 0) WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) - COALESCE(S.CTGRTQTY01, 0) ELSE 0 END ) END AS REQQTY /* 발주요청센터 반영 필요 발주량 해당수량 정보를 읽어서 발주 단위를 구한다. */ , GREATEST( 0, CASE S.REQCTKEY WHEN '05' THEN COALESCE(S.AVQTYCAL05, 0) /* 안성 */ WHEN '04' THEN COALESCE(S.AVQTYCAL04, 0) /* 부산 */ WHEN '01' THEN COALESCE(S.AVQTYCAL01, 0) /* 남사 */ ELSE 0 END ) AS B2BCARDBASEQTY
FROM ( SELECT F.* /* 발주 필요 가능일 : (가용일 + 센터 리드타임) - 현재 환산 가용일 [현재 환산가용일 : 총재고 / 일평균수량] */ , CASE WHEN F.CALAVDAYS IS NOT NULL THEN F.AVDAYS + F.CTLEADTIME - F.CALAVDAYS ELSE (CASE F.REQCTKEY WHEN '05' THEN F.CTLEADTIME05 + F.NEEDDAYS - F.NOWCNVRTAVDAYS WHEN '04' THEN F.CTLEADTIME04 + F.NEEDDAYS - F.NOWCNVRTAVDAYS WHEN '01' THEN F.CTLEADTIME01 + F.NEEDDAYS - F.NOWCNVRTAVDAYS ELSE 0 END) END AS PONEEDDAYS , COALESCE(F.AVDAYS, F.NEEDDAYS) AS AVDAYS_T /* B2B보장재고 */ , F.GRTIVDAYS01 * F.AVGOBQTY01 AS CTGRTQTY01 , F.GRTIVDAYS04 * F.AVGOBQTY04 AS CTGRTQTY04 , F.GRTIVDAYS05 * F.AVGOBQTY05 AS CTGRTQTY05 /* B2B센터 재고 + B2B입고예정정보 : B2B재고수량 */ , F.IBEXPCTQTY01 + AVQTY01 AS AVQTYCAL01 , F.IBEXPCTQTY04 + AVQTY04 AS AVQTYCAL04 , F.IBEXPCTQTY05 + AVQTY05 AS AVQTYCAL05 , CASE F.REQCTKEY WHEN '05' THEN F.CTLEADTIME05 WHEN '04' THEN F.CTLEADTIME04 WHEN '01' THEN F.CTLEADTIME01 ELSE F.CTLEADTIME END AS CTLEADTIME_T
FROM ( SELECT IC.ICKEY, IC.ICNM , IC.ASRTYN, IC.UNICYN ,IC.CTKEY, IC.OWKEY, IC.ACNM, IC.DSPYN ,IC.DLVRYYN , IC.SALESTATUS , IC.POABLEYN , IC.NEEDDAYS, IC.LCKEY , IC.SLPRC , /* 상품 정보 */ IC.REQORDERTYPE, IC.ANSUNGB2BPOCTG, IC.NAMSAB2BPOCTG, IC.BUSANB2BPOCTG, IC.CBMCLOSRNG , IC.OBFROMDAY , IC.OBTODAY , IC.OBQTYCRITCAL , IC.APLYDAYS , /* 발주구역 , 통계평균 */ IC.IC_EA, IC.IC_INN , IC.IC_CTN,IC.IC_CPP , IC.VOL, IC.MEASUREMENTYN ,/* 입수량 및 부피 정보 */ COALESCE(AV.QTY, 0) AS DAYQTY , COALESCE(ST.MONTHQTY, 0) AS MONTHQTY, COALESCE(B2BINFO.AVQTY01, 0) AS AVQTY01, COALESCE(B2BINFO.AVQTY04, 0) AS AVQTY04, COALESCE(B2BINFO.AVQTY05, 0) AS AVQTY05, /* B2B재고정보*/ COALESCE(B2BINFO.PREIBQTY01, 0) AS PREIBQTY01, COALESCE(B2BINFO.PREIBQTY04, 0) AS PREIBQTY04, COALESCE(B2BINFO.PREIBQTY05, 0) AS PREIBQTY05, /* B2B 미입고 수량 */ COALESCE(B2BINFO.AVGOBQTY01, 0) AS AVGOBQTY01, COALESCE(B2BINFO.AVGOBQTY04, 0) AS AVGOBQTY04, COALESCE(B2BINFO.AVGOBQTY05, 0) AS AVGOBQTY05, /* B2B 일평균 */ COALESCE(B2BCON.GRTIVDAYS01, 0) AS GRTIVDAYS01, COALESCE(B2BCON.GRTIVDAYS04, 0) AS GRTIVDAYS04, COALESCE(B2BCON.GRTIVDAYS05, 0) AS GRTIVDAYS05, /* B2B 보장일수 */ COALESCE(B2BCON.CTLEADTIME01, 0) AS CTLEADTIME01, COALESCE(B2BCON.CTLEADTIME04, 0) AS CTLEADTIME04, COALESCE(B2BCON.CTLEADTIME05, 0) AS CTLEADTIME05, /* B2B 리드타임*/ COALESCE(B2BCPP.CPP01, 0) AS CPP01, COALESCE(B2BCPP.CPP04, 0) AS CPP04, COALESCE(B2BCPP.CPP05, 0) AS CPP05, /* B2BCPP */ COALESCE(CRITSET.CTNCRIT, 0) AS CTNCRIT, COALESCE(CRITSET.INNCRIT, 0) AS INNCRIT, COALESCE(CRITSET.PLTCRIT, 0) AS PLTCRIT, /* 발주단위 정보 */ COALESCE(MD.REQQTY, 0) AS MDQTY , MD.CMT AS MDCMDT , COALESCE(RIV.AVQTY, 0) AS AVQTY , -- 현재고 COALESCE(IB.B2CIBQTY, 0) AS B2CIBQTY, -- 입고예정정보 -- 미리 계산할 수 있는 항목 정의 -- COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) AS TOTQTY, -- 총재고 ( COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER (PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0) ) AS TOTQTY, TRUNC(COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_INN, 0),0),2) INNDAYQTY , TRUNC(COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0),2) CTNDAYQTY , TRUNC(COALESCE(AV.QTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0) / NULLIF(COALESCE(IC_CPP, 0),0),2) AS PLTDAYQTY, -- 일평균수량 TRUNC(COALESCE(ST.MONTHQTY, 0) / NULLIF(COALESCE(IC_INN, 0),0),2) INNMONTHQTY , TRUNC(COALESCE(ST.MONTHQTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0),2) CTNMONTHQTY , TRUNC(COALESCE(ST.MONTHQTY, 0) / NULLIF(COALESCE(IC_CTN, 0),0) / NULLIF(COALESCE(IC_CPP, 0),0),2) AS PLTMONTHQTY, -- 월평균수량 CASE WHEN B2BINFO.IBEXPCTDAY01 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn}= 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY01, 0) ELSE 0 END AS IBEXPCTQTY01 , CASE WHEN B2BINFO.IBEXPCTDAY04 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY04, 0) ELSE 0 END AS IBEXPCTQTY04 , CASE WHEN B2BINFO.IBEXPCTDAY05 = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND #{b2bIbYn} = 'true' THEN COALESCE(B2BINFO.IBEXPCTQTY05, 0) ELSE 0 END AS IBEXPCTQTY05 , -- 입고 예정정보 -- ROUND(COALESCE(RE.CALAVDAYS, (COALESCE(RIV.AVQTY, 0)+COALESCE(IB.B2CIBQTY, 0)) / NULLIF(COALESCE(AV.QTY, 0),0)), 1) AS NOWCNVRTAVDAYS, ABS( ROUND(COALESCE(RE.CALAVDAYS, ((COALESCE(RIV.AVQTY, 0) + COALESCE(IB.B2CIBQTY, 0)) - COALESCE(SUM(COALESCE(RE.REQORDERQTY, 0)) OVER (PARTITION BY IC.ICKEY ORDER BY COALESCE(RE.SEQ, 1) ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING ), 0)) / NULLIF(COALESCE(AV.QTY, 0), 0)),1 ) ) AS NOWCNVRTAVDAYS, CASE WHEN TRIM(RE.REQCTKEY) IS NOT NULL THEN RE.REQCTKEY WHEN (COALESCE(B2BINFO.AVQTY05, 0)=0 AND COALESCE(B2BINFO.AVQTY01, 0)=0 AND COALESCE(B2BINFO.AVQTY04, 0)=0) THEN NULL WHEN (COALESCE(B2BINFO.AVQTY05, 0)-COALESCE(B2BINFO.AVGOBQTY05, 0)*COALESCE(B2BCON.GRTIVDAYS05, 0)) >= (COALESCE(AV.QTY, 0)*(3+COALESCE(B2BCON.CTLEADTIME05, 0))) THEN '05' WHEN (COALESCE(B2BINFO.AVQTY01, 0)-COALESCE(B2BINFO.AVGOBQTY01, 0)*COALESCE(B2BCON.GRTIVDAYS01, 0)) >= (COALESCE(AV.QTY, 0)*(3+COALESCE(B2BCON.CTLEADTIME01, 0))) THEN '01' WHEN (COALESCE(B2BINFO.AVQTY04, 0)-COALESCE(B2BINFO.AVGOBQTY04, 0)*COALESCE(B2BCON.GRTIVDAYS04, 0)) >= (COALESCE(AV.QTY, 0)*(3+COALESCE(B2BCON.CTLEADTIME04, 0))) THEN '04' ELSE CASE WHEN COALESCE(B2BINFO.AVQTY05, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY01, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '05' WHEN COALESCE(B2BINFO.AVQTY01, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY04, 0)) THEN '01' WHEN COALESCE(B2BINFO.AVQTY04, 0) >= GREATEST(COALESCE(B2BINFO.AVQTY05, 0), COALESCE(B2BINFO.AVQTY01, 0)) THEN '04' ELSE '05' END END AS REQCTKEY, /* 발주요청센터 */ -- RE 커럼 정보 추가 RE.REQORDERDAY, RE.UPLOADYN, RE.REQORDERSTATUS ,COALESCE(RE.SEQ, 1) AS SEQ ,RE.REQORDERUNIT , RE.DLVYREQORDERUNIT , CASE WHEN RE.REQORDERSTATUS NOT IN ( '01','02','03') -- 요청, 확정, 취소 AND COALESCE(RE.RECALCYN, 'N') = 'Y' THEN NULL ELSE RE.REQORDERQTY END AS REQORDERQTY, RE.RECALCYN, COALESCE(RE.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN , RE.AVDAYS AS AVDAYS , -- 발주 가용일 RE.CALAVDAYS AS CALAVDAYS , --환산가용일 RE.CTLEADTIME AS CTLEADTIME , -- 발주요청센터 리드타임 RE.REQORDERAR, RE.INSERTDATE , RE.INSERTURKEY , RE.UPDATEDATE ,RE.UPDATEURKEY FROM ( SELECT A.OWKEY , B.CTKEY , A.ICKEY, A.ICNM , A.ASRTYN, A.UNICYN ,A.SLPRC , AC.ACNM , A.DSPYN ,A.DLVRYYN , A.SALESTATUS , A.POABLEYN , COALESCE(B.NEEDDAYS, 0) AS NEEDDAYS , LC.LCKEY ,LC.ANSUNGB2BPOCTG, LC.NAMSAB2BPOCTG, LC.BUSANB2BPOCTG , LC.CBMCLOSRNG , B.REQORDERTYPE , E.OBFROMDAY , E.OBTODAY , E.OBQTYCRITCAL , E.APLYDAYS , B.IC_EA , B.IC_INN , B.IC_CTN , B.IC_CPP , B.VOL , UT.MEASUREMENTYN FROM TORDER_MST_IC A INNER JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY LEFT JOIN TORDER_MST_ICUTXTYPE UT ON A.OWKEY = UT.OWKEY AND A.ICKEY = UT.ICKEY AND UT.ICUNITTYPE ='EA' LEFT JOIN TORDER_MST_AC AC ON A.OWKEY = AC.OWKEY AND A.ACKEY = AC.ACKEY LEFT JOIN ( SELECT C.OWKEY,C.CTKEY , D.LCKEY ,C.ICKEY, D.ANSUNGB2BPOCTG, D.NAMSAB2BPOCTG, D.BUSANB2BPOCTG , D.CBMCLOSRNG FROM TORDER_MST_ICXCT C LEFT JOIN TORDER_MST_LC D ON C.CTKEY = D.CTKEY AND C.LCKEY = D.LCKEY ) LC ON LC.OWKEY= A.OWKEY AND LC.CTKEY = B.CTKEY AND LC.ICKEY = A.ICKEY LEFT JOIN TORDER_MST_OBAVGQTY E ON A.OWKEY =E.OWKEY AND B.CTKEY = E.CTKEY AND A.ICKEY = E.ICKEY WHERE A.OWKEY = #{owkey} AND B.CTKEY =#{CTKEY} AND B.REQORDERTYPE ='03' AND A.POABLEYN ='Y' AND A.ICSTATUSDIV != '9' AND ( A.ASRTYN = 'N' OR ( A.ASRTYN = 'Y' AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = A.OWKEY AND Z.ASRTREPKEY = A.ICKEY AND Z.QTY > 0 ) ) )
AND A.ICKEY IN
#{item}
AND A.ASRTYN = #{ASRTYN}
AND A.DSPYN = #{DSPYN}
AND A.SALESTATUS = #{SALESTATUS}
AND A.OLNICDIV = #{OLNICDIV}
AND A.DSBTGRADE = #{DSBTGRADE}
) IC LEFT JOIN ( SELECT R.OWKEY , R.CTKEY , COALESCE(Y.ASRTREPKEY, R.ICKEY) AS ICKEY , SUM(R.AVQTY) AS AVQTY FROM ( SELECT A.OWKEY, A.CTKEY, A.ICKEY, SUM(A.AVQTY) AS AVQTY FROM TORDER_INFO_REQORDERIV A JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY AND A.CTKEY = B.CTKEY WHERE A.OWKEY = #{owkey} AND A.CTKEY =#{CTKEY} GROUP BY A.OWKEY, A.CTKEY, A.ICKEY ) R LEFT JOIN TORDER_MST_ASRT Y ON Y.OWKEY = R.OWKEY AND Y.ASRTKEY = R.ICKEY AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = Y.OWKEY AND Z.ASRTREPKEY = Y.ASRTREPKEY AND Z.QTY > 0 )
GROUP BY R.OWKEY, R.CTKEY, COALESCE(Y.ASRTREPKEY, R.ICKEY) ) RIV ON IC.OWKEY = RIV.OWKEY AND IC.CTKEY = RIV.CTKEY AND IC.ICKEY = RIV.ICKEY LEFT JOIN TORDER_INFO_OBSTAT_AVG AV --일평균 출고량 ON IC.OWKEY = AV.OWKEY AND IC.CTKEY = AV.CTKEY AND IC.ICKEY = AV.ICKEY LEFT JOIN ( SELECT A.OWKEY, A.CTKEY, A.ICKEY , DATE_TRUNC('day', SUM(A.QTY) / 30)::DATE AS MONTHQTY FROM TORDER_INFO_ORDER_STAT A JOIN REQ_MST B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY WHERE A.OWKEY = #{owkey} AND A.CTKEY =#{CTKEY} AND A.CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '30 days', 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') GROUP BY A.OWKEY, A.CTKEY, A.ICKEY ) ST ON IC.OWKEY = ST.OWKEY AND IC.CTKEY = ST.CTKEY AND IC.ICKEY = ST.ICKEY LEFT JOIN ( SELECT A.ICKEY -- AVQTY 가용재고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY05 -- PREIBQTY 미입고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY05 -- IBEXPCTDAY 입고예정일자 , MAX(CASE WHEN A.CTKEY = '01' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY01 , MAX(CASE WHEN A.CTKEY = '04' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY04 , MAX(CASE WHEN A.CTKEY = '05' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY05 -- IBEXPCTQTY 입고예정수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY05 -- AVGOBQTY 일평균출고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY05 -- B2B 센터재고보장일수
FROM TORDER_INFO_B2BAVGOBQTY_REQORDER A INNER JOIN TORDER_MST_CT B ON A.CTKEY = B.CTKEY JOIN REQ_MST C ON A.ICKEY = C.ICKEY WHERE A.CRITDAY = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND A.AVQTY > 0 GROUP BY A.ICKEY ) B2BINFO ON IC.ICKEY = B2BINFO.ICKEY LEFT JOIN ( SELECT MAX(CASE WHEN CTKEY = '01' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS05 -- 리드타임 , MAX(CASE WHEN CTKEY = '01' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME05 FROM TORDER_MST_CT ) B2BCON ON 1=1 LEFT JOIN ( SELECT A.ICKEY , COALESCE(MAX(CASE WHEN A.CTKEY = '01' THEN CPP END), 1) AS CPP01 , COALESCE(MAX(CASE WHEN A.CTKEY = '04' THEN CPP END), 1) AS CPP04 , COALESCE(MAX(CASE WHEN A.CTKEY = '05' THEN CPP END), 1) AS CPP05 FROM TORDER_MST_ICXB2BCPP A JOIN REQ_MST B ON A.ICKEY = B.ICKEY GROUP BY A.ICKEY ) B2BCPP ON IC.ICKEY = B2BCPP.ICKEY LEFT JOIN ( SELECT OWKEY , CTKEY , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'CTN' THEN CRITSET END), 0.5) AS CTNCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'PLT' THEN CRITSET END), 0.5) AS PLTCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'INN' THEN CRITSET END), 0.5) AS INNCRIT FROM TORDER_MST_REQORDER_CNTRUNIT WHERE OWKEY = #{owkey} AND CTKEY = #{CTKEY} AND DELYN = 'N' GROUP BY OWKEY, CTKEY ) CRITSET ON IC.OWKEY = CRITSET.OWKEY AND IC.CTKEY = CRITSET.CTKEY LEFT JOIN TORDER_INFO_MD_RDEQODRDER MD ON IC.OWKEY = MD.OWKEY AND IC.CTKEY = MD.CTKEY AND IC.ICKEY = MD.ICKEY AND MD.REQORDERDAY= COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) LEFT JOIN TORDER_INFO_REQORDER RE ON IC.OWKEY = RE.OWKEY AND IC.CTKEY = RE.CTKEY AND IC.ICKEY = RE.ICKEY AND RE.URGENCYREQORDERYN ='N' AND RE.REQORDERDAY= COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) LEFT JOIN ( SELECT H.OWKEY, D.ICKEY, SUM(COALESCE(EXPCTQTY, 0)) AS B2CIBQTY FROM TORDER_INFO_SO_HD H INNER JOIN TORDER_INFO_SO_DT D ON H.OWKEY = D.OWKEY AND H.SOHDKEY = D.SOHDKEY INNER JOIN TORDER_MST_ORTYPE O ON H.OWKEY = O.OWKEY AND H.ORDERTYPECD = O.ORDERTYPECD WHERE O.POCALINCYN = 'Y' AND H.DLVYEXPCTDAY = COALESCE(#{REQORDERDAY}, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')) AND H.OWKEY = #{owkey} AND H.CTKEY = #{CTKEY} GROUP BY H.OWKEY, D.ICKEY )IB ON IC.OWKEY = IB.OWKEY AND IC.ICKEY = IB.ICKEY WHERE 1 = 1 ) F
) S ) T ) X LEFT JOIN TORDER_MST_CT CT ON X.REQCTKEY = CT.CTKEY LEFT JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='POSTATUS' AND INSERTSYSTM = 'OMS' AND LAKEY = 'KOR' ) Y ON X.OWKEY = Y.OWKEY AND Y.COMDTKEY = X.REQORDERSTATUS LEFT JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='REQORDERTYPE' AND INSERTSYSTM = 'OMS' AND LAKEY = 'KOR' ) Z ON X.OWKEY = Z.OWKEY AND Z.COMDTKEY = X.REQORDERTYPE LEFT JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='CD_00203' AND INSERTSYSTM = 'MAL' AND LAKEY = 'KOR' ) ZZ ON X.OWKEY = ZZ.OWKEY AND ZZ.COMDTKEY = X.SALESTATUS WHERE X.OWKEY = #{owkey} AND ( X.AVQTY05 > 0 OR X.AVQTY04> 0 OR X.AVQTY01 > 0 )
AND COALESCE(x.NOWCNVRTAVDAYS, 0) <= COALESCE(X.AVDAYS_T, 0)
AND COALESCE(X.NOWCNVRTAVDAYS, 0) > COALESCE(X.AVDAYS_T, 0) AND COALESCE(X.DAYQTY, 0) > 0
AND X.REQORDERSTATUS = #{REQORDERSTATUS}
AND X.REQCTKEY = #{REQCTKEY}
AND COALESCE(X.NOWCNVRTAVDAYS, 0) >= #{CALAVDAYS_FROM}
AND COALESCE(X.NOWCNVRTAVDAYS, 0) <= #{CALAVDAYS_FROM}
AND COALESCE(X.PONEEDDAYS, 0) >= #{PONEEDDAY_FROM}
AND COALESCE(X.PONEEDDAYS, 0) >= #{PONEEDDAY_TO}
AND (CASE WHEN X.REQORDERUNIT IS NOT NULL THEN X.REQORDERUNIT WHEN X.UPLOADYN ='Y' THEN CASE /* PLT 판단 : 수량 / CTN / CPP */ WHEN X.IC_CTN > 0 AND MOD( X.REQORDERQTY, X.IC_CTN * CASE X.REQCTKEY WHEN '01' THEN X.CPP01 WHEN '04' THEN X.CPP04 WHEN '05' THEN X.CPP05 ELSE X.IC_CPP END ) = 0 THEN 'PLT' /* CTN 판단 : 수량 / CTN */ WHEN X.IC_CTN > 0 AND MOD(X.REQORDERQTY, X.IC_CTN) = 0 THEN 'CTN' /* 나머지는 INN */ ELSE 'INN' END ELSE /* 정상 후보 비교 로직 (기존 유지) */ CASE WHEN X.CAND_QTY_PLT = 0 AND X.CAND_QTY_CTN = 0 THEN 'INN' WHEN X.CAND_QTY_PLT >= X.CAND_QTY_CTN AND X.CAND_QTY_PLT >= X.CAND_QTY_INN THEN 'PLT' WHEN X.CAND_QTY_CTN >= X.CAND_QTY_INN THEN 'CTN' ELSE 'INN' END END ) =#{REQORDERUNIT}

		/* oms-po-poPlanReq-sql-oracle.xml - checkPoPlanReq */
