		/* oms-po-poPlanReq-sql-oracle.xml - updatePoPlanReqStatus */
		UPDATE TORDER_INFO_REQORDER
		   SET UPDATEDATE       = #{sysdate}
             , UPDATEURKEY      = #{surkey}

		     , REQORDERSTATUS   = CASE WHEN COALESCE(#{reqorderexceptyn}, 'N') = 'Y' THEN '03'
                                       ELSE #{reqorderstatus}
                                  END


		     , REQORDEREXCEPTYN = #{reqorderexceptyn}


		     , REQORDERNO = #{reqorderno}


		     , CNFRMREQORDERQTY = #{reqorderqty}


			 , IBEXPCTDAY =  CASE WHEN  #{reqorderstatus} ='02' THEN  #{ibexpctday} ELSE NULL END


			 , IBEXPCTDAY =  CASE WHEN  #{reqorderstatus} ='02' THEN  SUBSTR(#{reqorderno}, 1, 8) ELSE NULL END

		WHERE OWKEY             = #{owkey}
	      AND CTKEY             = #{ctkey}
	      AND REQORDERDAY       = #{reqorderday}
          AND ICKEY             = #{ickey}
          AND REQORDERTYPE      = #{reqordertype}
          AND URGENCYREQORDERYN = #{urgencyreqorderyn}
          AND SEQ               = #{seq}

