		   SET ICTGT            = #{ictgt}
             , REQORDERAR       = #{reqorderar}
             , REQORDERNO       = #{reqorderno}
             , REQORDERSTATUS   = CASE WHEN  #{reqorderexceptyn} ='N' THEN  #{reqorderstatus} ELSE REQORDERSTATUS END
             , ABLEREQORDERYN   = #{ablereqorderyn}
             , UNICYN           = #{unicyn}
             , AVGOBQTY         = #{eadayavgobqty}
             , AVGOBFROMDAY     = #{avgobfromday}
             , AVGOBTODAY       = #{avgobtoday}
             , AVGAPLYDAYS      = #{avgaplydays}
             , AVQTY            = #{avqty}
             , IBEXPCTQTY       = #{b2cibqty}
             , REQCTKEY         = #{reqctkey}
             , CALAVDAYS        = #{calavdays}
             , DLVYREQORDERUNIT = #{dlvyreqorderunit}
             , REQORDERQTY      = #{reqorderqty}
             , CNFRMREQORDERQTY = #{cnfrmreqorderqty}
             , AVDAYS           = #{avdays}
             , REQORDERUNIT     = #{reqorderunit}
             , RECALCYN			= #{recalcyn}
             , CTLEADTIME       = #{ctleadtime}

             , IBEXPCTDAY       = #{ibexpctday}

             , UPDATEDATE       = #{sysdate}
             , UPDATEURKEY      = #{surkey}
		WHERE OWKEY             = #{owkey}
	      AND CTKEY             = #{ctkey}
	      AND REQORDERDAY       = #{reqorderday}
          AND ICKEY             = #{ickey}
          AND REQORDERTYPE      = #{reqordertype}
