/* oms-po-poPlanReq-sql-oracle.xml - selectExcelUploadVaild */
WITH UPLD_IC AS ( SELECT /* hint: MATERIALIZE */ DISTINCT ICKEY FROM TORDER_UPLOAD_REQORDER WHERE UPLDKEY = #{upldkey} ), REQ AS ( SELECT /* hint: MATERIALIZE */ OWKEY, CTKEY, REQCTKEY, ICKEY, REQORDERDAY,REQORDERTYPE, CTLEADTIME, AVDAYS, CALAVDAYS, URGENCYREQORDERYN FROM TORDER_INFO_REQORDER WHERE OWKEY='DAISO' AND REQORDERTYPE='03' AND REQORDERDAY=TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') )
SELECT CASE WHEN EXREQODER = '00' THEN 'TXT_IS_EXISTS_DATA' WHEN F.OLNCTKEY IS NULL THEN 'TXT_OLNCTKEY_NULL' WHEN F.OFLNCTKEY IS NULL THEN 'TXT_OFLNCTKEY_NULL' WHEN F.ICKEY IS NULL THEN 'TXT_ICKEY_NULL' WHEN POICKEY IS NULL THEN 'TXT_NO_PO_IC' WHEN ONLNCTKEY IS NULL THEN 'TXT_NO_ONLINE_CT' WHEN OFFLNCTKEY IS NULL THEN 'TXT_NO_OFFLINE_CT' WHEN IVRFLCTNEEDQTY < REQORDERQTY THEN 'TXT_REQORDQTY_LARGE' WHEN DPCTCHEK > 1 THEN 'TXT_DUPLICATE_ICKEY' END AS ERRCD , F.UPLDKEY , F.UPLDSEQ FROM ( SELECT T.UPLDKEY , T.UPLDSEQ , T.OLNCTKEY , T.OFLNCTKEY , T.ICKEY , T.REQORDERQTY , T.DELYN , T.B2BAVQTY + T.IBEXPCTQTY AS IVRFLCTNEEDQTY , T.DPCTCHEK , T.EXREQODER , T.POICKEY , T.ONLNCTKEY , T.OFFLNCTKEY FROM ( SELECT A.UPLDKEY , A.UPLDSEQ , A.OLNCTKEY , A.OFLNCTKEY , A.ICKEY , A.REQORDERQTY , CASE WHEN RE.ICKEY IS NOT NULL AND RE.REQORDERTYPE ='03' AND RE.URGENCYREQORDERYN ='N' AND REQORDERDAY = TO_CHAR( CURRENT_TIMESTAMP, 'YYYYMMDD') AND A.OFLNCTKEY = RE.REQCTKEY THEN '00' ELSE '01' END EXREQODER , COALESCE(RE.CTLEADTIME, REQCT.CTLEADTIME) AS CTLEADTIME , COALESCE(RE.AVDAYS, PO_IC.NEEDDAYS) AS AVDAYS , COALESCE(RE.CALAVDAYS, DATE_TRUNC('day', (COALESCE(RIV.AVQTY, 0) + COALESCE(B2C_IB.B2C_IB_QTY, 0)) / COALESCE(AV.QTY, 1))::DATE) AS NOWCNVRTAVDAYS , COALESCE(RIV.AVQTY, 0) AS AVQTY , COALESCE(AV.QTY, 0) AS AVGQTY , COALESCE(B2B_REQ.AVQTY, 0) AS B2BAVQTY , COALESCE(B2B_REQ.AVGOBQTY, 0) AS B2BAVGOBQTY , CASE WHEN B2B_REQ.IBEXPCTDAY = TO_CHAR( CURRENT_TIMESTAMP, 'YYYYMMDD') THEN B2B_REQ.IBEXPCTQTY ELSE 0 END IBEXPCTQTY , A.DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY , PO_IC.ICKEY AS POICKEY , CT.CTKEY AS ONLNCTKEY , REQCT.CTKEY AS OFFLNCTKEY , REQCT.GRTIVDAYS , Z.DPCTCHEK FROM TORDER_UPLOAD_REQORDER A LEFT JOIN ( SELECT X.OWKEY, X.ICKEY, X.ICSTATUSDIV, X.POABLEYN, X.ASRTYN, X.SALESTATUS, Y.CTKEY, Y.REQORDERTYPE, Y.NEEDDAYS, Y.SAFEIVDAYSINCYN, Y.TIMESERIESYN, Y.AUTOCHGYN FROM TORDER_MST_IC X INNER JOIN TORDER_MST_REQORDER Y ON X.OWKEY = Y.OWKEY AND X.ICKEY = Y.ICKEY AND Y.REQORDERTYPE ='03' WHERE X.OWKEY = #{owkey} AND ( X.ASRTYN ='N' OR EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = X.OWKEY AND Z.ASRTREPKEY = X.ICKEY AND Z.QTY > 0 ) ) -- 자상품 여부 AND X.POABLEYN ='Y' -- 몰에서 주는 발주 가능여부 AND X.ICSTATUSDIV != '9' -- EPR에서 주는 단종이 아닌경우 ) PO_IC ON PO_IC.OWKEY = #{owkey} AND A.OLNCTKEY = PO_IC.CTKEY AND A.ICKEY = PO_IC.ICKEY LEFT JOIN REQ RE ON A.OLNCTKEY = RE.CTKEY AND A.OFLNCTKEY = RE.REQCTKEY AND A.ICKEY = RE.ICKEY AND RE.REQORDERTYPE ='03' AND RE.REQORDERDAY = TO_CHAR( CURRENT_TIMESTAMP, 'YYYYMMDD') AND RE.OWKEY = #{owkey} LEFT JOIN TORDER_MST_CT CT ON A.OLNCTKEY = CT.CTKEY AND CT.CTTYPE = '01' LEFT JOIN TORDER_MST_CT REQCT ON A.OFLNCTKEY = REQCT.CTKEY AND REQCT.CTTYPE = '02' LEFT JOIN ( SELECT Z.OWKEY , Z.CTKEY , Z.GRPBASE AS ICKEY , SUM( Z.AVQTY) AS AVQTY FROM ( SELECT X.CTKEY , X.OWKEY , X.ICKEY , X.AVQTY , COALESCE(Y.ASRTREPKEY, X.ICKEY) GRPBASE FROM TORDER_INFO_REQORDERIV X INNER JOIN UPLD_IC W ON W.ICKEY = X.ICKEY LEFT JOIN TORDER_MST_ASRT Y ON X.OWKEY = Y.OWKEY AND X.ICKEY = Y.ASRTKEY AND EXISTS ( SELECT 1 FROM TORDER_MST_ASRT Z WHERE Z.OWKEY = Y.OWKEY AND Z.ASRTREPKEY = Y.ASRTREPKEY AND Z.QTY > 0 )
) Z GROUP BY Z.OWKEY , Z.CTKEY , Z.GRPBASE ) RIV ON A.OLNCTKEY = RIV.CTKEY AND RIV.OWKEY = #{owkey} AND A.ICKEY = RIV.ICKEY LEFT JOIN ( SELECT H.OWKEY, D.ICKEY, SUM(COALESCE(EXPCTQTY, 0)) AS B2C_IB_QTY FROM TORDER_INFO_SO_HD H INNER JOIN TORDER_INFO_SO_DT D ON H.OWKEY = D.OWKEY AND H.SOHDKEY = D.SOHDKEY INNER JOIN TORDER_MST_ORTYPE O ON H.OWKEY = O.OWKEY AND H.ORDERTYPECD = O.ORDERTYPECD INNER JOIN UPLD_IC W ON W.ICKEY = D.ICKEY WHERE O.POCALINCYN = 'Y' AND H.DLVYEXPCTDAY = TO_CHAR( CURRENT_TIMESTAMP ,'YYYYMMDD') GROUP BY H.OWKEY, D.ICKEY )B2C_IB ON B2C_IB.OWKEY = #{owkey} AND PO_IC.ICKEY = B2C_IB.ICKEY LEFT JOIN TORDER_INFO_OBSTAT_AVG AV ON AV.OWKEY = #{owkey} AND A.OLNCTKEY = AV.CTKEY AND A.ICKEY = AV.ICKEY LEFT JOIN TORDER_INFO_B2BAVGOBQTY_REQORDER B2B_REQ ON A.OFLNCTKEY = B2B_REQ.CTKEY AND A.ICKEY = B2B_REQ.ICKEY AND B2B_REQ.CRITDAY = TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') JOIN( SELECT COUNT(1) AS DPCTCHEK , ICKEY , UPLDKEY FROM TORDER_UPLOAD_REQORDER WHERE UPLDKEY= #{upldkey} GROUP BY ICKEY , UPLDKEY ) Z ON A.UPLDKEY = Z.UPLDKEY AND A.ICKEY = Z.ICKEY
WHERE A.UPLDKEY = #{upldkey} ) T ) F

